import programData from '../system/mock/programData.json' // restful api를 사용하지 않을 경우
import request from '@/utils/request'
import { isUseAPI } from '@/utils/check'

export function getProgramData(param,isNotify) {
  let isTest = false

  if (!isUseAPI() || isTest) {
    return new Promise(function(resolve, reject) {
      let res = programData
      resolve(res.list)
    })
  }
  return request({
    url: `/api/getProgramData`,
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: param,
    Notify: { use: isNotify, apitype: 'searched' } //searched, saved,deleted
  })
}

export function updateProgramData(param,isNotify) {
  return request({
    url: `/api/updateProgramData`,
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: param,
    Notify: { use: isNotify, apitype: 'saved' } //searched, saved,deleted
  })
}

export function deleteProgramData(param,isNotify) {
  return request({
    url: '/api/deleteProgramData',
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: param,
    Notify: { use: isNotify, apitype: 'deleted' } //searched, saved,deleted
  })
}
