<template>
  <div>
    <!-- <VueToastify></VueToastify>
    <slot></slot> -->
    <!--the appropriate input should go here-->
    <!-- 각 페이지에 공통으로 처리할 부모 페이지 구성입니다 BY LYJ -->
    <!-- 1. 페이지 권한 공통처리 BY LYJ -->
  </div>
</template>
<script>
//function
// import { getMenuManage } from '@/api/setting/menuManage'
// import { getAuthMenuById } from '@/api/common/menu'
import { getUserCd, getGrpAuthCd, getCompId, getCompNm } from '@/utils/token'
import sessionStore from '@/utils/sessionStore'
import { getGrpAuthOfMenu } from '@/api/common/commonApi'

export default {
  name: 'baseview',
  components: {},
  data: function() {
    return {
      childComponent: null,
      topIndex: this.$route.params == undefined ? '' : this.$route.params.topIndex,
      topMenuId: this.$route.params == undefined ? '' : this.$route.params.tMenu,
      menuid: this.$route.params == undefined ? '' : this.$route.params.selMenuid,
      grid: {
        width: '100%',
        columnHidingEnabled: false
      },
      pager: {
        visible: true,
        showNavButtons: true,
        showPageSizeSelector: true,
        pageCount: 15,
        showInfo: true,
        navigationMode: 'PagerNavigationMode.Auto',
        displayMode: 'full', //full, compact
        visibleNumericButtonCount: '4',
        pageSizes: [5, 10, 'all']
      },
      comp: {
        id: getCompId()
      },
      menuAuth: {
        search: 'Y',
        save: 'N',
        print: 'N',
        delete: 'N'
      }
    }
  },
  created() {
    //remove event
    this.$EventBus.$off(`${this.menuid}_RouteRefresh`)
    this.$EventBus.$off(`${this.menuid}_notifyAction`)

    //20220520 LYJ
    //recieved common popupNotify event handling
    //type:yes, no, confirm
    //console.log(`${this.menuid}_notifyAction event start`, this.$EventBus)
    this.$EventBus.$on(`${this.menuid}_notifyAction`, notify => {
      //console.log(notify)
      if (notify.action != undefined) {
        // console.log('enter')
        notify.action(this.$root.$children[0].$children[0].$children[0].$refs['componentRef'])
      }
    })

    
    this.$EventBus.$on(`${this.menuid}_RouteRefresh`, info => {
      ////console.log('RouteRefresh event received!  ')
      ////console.log('menuid:' + this.menuid)
      this.menuid = this.$route.params == undefined ? '' : this.$route.params.selMenuid
      this.RouteRefresh()
    })
  },
  computed: {
    PagerAttr() {
      return this.pager
    }
  },
  mounted() {
    //getGrpAuthCd()
    let param = { grpAuthCd: getGrpAuthCd(), menuId: this.menuid }
    getGrpAuthOfMenu(param, false)
      .then(res => {
        if (res.list && res.list.length > 0) {
          this.menuAuth.search = res.list[0].schAh
          this.menuAuth.save = res.list[0].savAh
          this.menuAuth.print = res.list[0].exlAh
          this.menuAuth.delete = res.list[0].delAh
        }
      })
      .finally(() => {})
  },
  activated() {
    ////console.log('baseview activated')
    this.$EventBus.$emit('refreshMenu', { topIndex: this.topIndex, topMenuId: this.topMenuId })
  },
  deactivated() {
    ////console.log('baseview deactivated')
  },
  methods: {
    ignoreKorean(e, ref) {
      const koreanRegex = /[ㄱ-ㅎ|ㅏ-ㅣ|가-힣|a-z|A-Z]/
      try {
        if (koreanRegex.test(e.event.originalEvent.data)) this.$refs[ref].instance.closeEditCell()
        this.vToastify(this.$t('msgOnlyNum'), 'warn')
      } catch (e) {
        return
      }
    },
    BaseInitialize() {
      //console.log('BaseInitialize menu id:' + this.menuid)
      //console.log(this.$route.params)
    },
    RouteRefresh() {
      // console.log('asdf')
      //자식에서 재정의하면 오버라이드됩니다.
      //자식에서 재정의해서 필요코드 구현하세요.\

      //console.log('메뉴 클릭시 자식에서 재정의해서 필요코드 구현하세요 ! 메뉴id: ' + this.menuid)
      //다중상속(mixins)일경우는 method override가 되지 않으므로 필요할경우 다음 이벤트를 on해서 쓰고 destroy할때 off 단디 해주삼~ by LYJ
      this.$EventBus.$emit(`${this.menuid}_ChildRouteRefresh`)
    },
    //20220406 LYJ 컴포넌트간의 통신을 위한 이벤트 등록(각 담당자들은 요런방식으로 받아서 사용하세요)
    setCompInfo(info) {
      // //console.log(`Event Received! : ${msg}`)
      this.comp.id = info.compId
      //console.log('Event Received! : compId : ' + this.comp.id)
    },
    // getMenuAuth() {
    //   return this.menuAuth
    // },
    // showLoadPanel() {
    //   this.loadingVisible = true
    // },
    //
    openLoading(div) {
      // console.log('openLoading')
      this.$EventBus.$emit('openLoading', div)
    },
    //
    endLoading() {
      // console.log('endLoading')
      this.$EventBus.$emit('endLoading')
    },

    //MessageType: info, warn, error, question
    vToastify(body, messageType) {
      ////console.log({ title: title, body: body, popupType: 'confirm', messageType: messageType, useLoding: false })
      this.$EventBus.$emit('popupNotify', { body: body, popupType: 'confirm', messageType: messageType, useLoding: false })
    },
    vToastifyPrompt(body, messageType, yesAction, noAction, useLoding) {
      // console.log({
      //   //title: title,
      //   body: body,
      //   popupType: 'yesno',
      //   messageType: messageType,
      //   yesAction: yesAction,
      //   noAction: noAction,
      //   useLoding: useLoding
      // })
      this.$EventBus.$emit('popupNotify', {
        body: body,
        popupType: 'yesno',
        messageType: messageType,
        yesAction: yesAction,
        noAction: noAction,
        useLoding: useLoding
      })
    },

    getUserCd() {
      return getUserCd()
    },
    //this.comp 정보가 제대로 안불러질경우 이 함수를 가져다 쓰세요
    getCompId() {
      return  getCompId()
    },
    getCompNm() {
      return this.$store.state.app.compNm ? this.$store.state.app.compNm : getCompNm()
    },
    ///////////////////////////////////////
    /*           Dev grid Event          */
    ///////////////////////////////////////
    baseHeaderFilterIconClick() {
      //헤더필터 처리
      let childrenCompoent = this.$parent.$children
      let gridComponent = childrenCompoent.find(element => {
        return element.instance ? element.instance.NAME === 'dxDataGrid' : false
      })

      // 필터 초기화
      gridComponent.instance.clearFilter()
      // 현재의 필터 상태
      let filterState = gridComponent.instance.option('headerFilter.visible')
      gridComponent.instance.option('headerFilter.visible', !filterState)
    },
    baseFilterIconClick() {
      // 그리드 찾기
      let childrenCompoent = this.$parent.$children
      let gridComponent = childrenCompoent.find(element => {
        return element.instance ? element.instance.NAME === 'dxDataGrid' : false
      })

      // 필터 초기화
      gridComponent.instance.clearFilter()
      // 현재의 필터 상태
      let filterState = gridComponent.instance.option('filterRow.visible')
      gridComponent.instance.option('filterRow.visible', !filterState)
    },
    baseFindIconClick(value) {
      // 그리드 찾기
      let childrenCompoent = this.$parent.$children
      let gridComponent = childrenCompoent.find(element => {
        return element.instance ? element.instance.NAME === 'dxDataGrid' : false
      })

      // 검색
      gridComponent.instance.searchByText(value)
    },
    initSearchPanel(gridRef) {
      let childrenCompoent = gridRef.$parent.$children
      let searchComponent = childrenCompoent.find(element => {
        return element.name ? element.name === 'iSearchPanel' : false
      })
      if (searchComponent != null) {
        searchComponent.initSearchPanel()
      }
    },

    ///////////////////////////////////////
    /*             report Event          */
    ///////////////////////////////////////
    downloadReport(res) {
      let link = document.createElement('a')
      // 객체를 만들어서 생성
      let objectUrl = window.URL.createObjectURL(res.data)
      link.href = objectUrl
      link.download = res.headers.filename
      link.click()
    }
  },
  beforeDestroy() {
    console.log(`${this.menuid}event beforeDestroy`)
    this.$EventBus.$off(`${this.menuid}_RouteRefresh`)
  }
}
</script>
<style lang="scss" scoped></style>
