//위험성평가 실시규정에 대한 서로다른 컴포넌트간의 데이타 수집을 위해서
export default {
  namespaced: true,

  //data
  state: {
    doc_no: '',
    rev_no: '',
    enactment_dt: '',
    rev_dt: '',
    rev_reason: '',
    approver: '',
    drafter: '',
    safety_policy: '',
    implementation_goal: '',
    objectives: '',
    safety_scope: '',
    orgn_order: '',
    orgn1: '',
    orgn2: '',
    orgn3: '',
    orgn4: '',
    orgn5: '',
    orgn6: '',
    orgn7: '',
    orgn8: '',
    orgn9: '',
    orgn10: '',
    rnr1: '',
    rnr2: '',
    rnr3: '',
    rnr4: '',
    rnr5: '',
    rnr6: '',
    rnr7: '',
    rnr8: '',
    rnr9: '',
    rnr10: '',
    assessment_target: '',
    implementation_timing: '',
    implementation_method: '',
    promotion_procedure: '',
    risk_estimation: '',
    public_method: '',
    notice: '',
    record_method: ''
  },

  //데이터 변경시
  mutations: {
    CHANGE_VALUE: (state, { key, value }) => {
      // eslint-disable-next-line no-prototype-builtins
      if (state.hasOwnProperty(key)) {
        state[key] = value
      }
    },
    GET_ALL_VALUES: state => {
      return state
    },
    GET_VALUE: (state, key) => {
      return state[key]
    }
  },

  //methods
  actions: {
    changeValue({ commit }, data) {
      commit('CHANGE_VALUE', data)
    },
    getAllValues() {
      commit('GET_ALL_VALUES')
    },
    getValue() {
      commit('GET_VALUE', key)
    }
  }
}
