<template>
  <div class="userInfoChange v-application">
    <v-card :key="refreshKey" class="pa-0 popup-card">
      <div class="popup-content">
        <v-sheet height="20" max-height="20" color="transparent" class="pl-2 d-flex align-center justify-start">
          <small style="color:red;" v-if="error != ''">{{ error }}</small>
        </v-sheet>
        <div>
          <v-row no-gutters class="px-2">
            <v-col cols="4" class="pa-0 pt-4 pb-6">{{ '*' + $t(headers[0].text) }}</v-col>
            <v-col class="pa-0 pt-2">
              <v-text-field v-model="params.compId" clearable @change="changeValueComp"></v-text-field>
            </v-col>
          </v-row>
          <v-row no-gutters class="px-2">
            <v-col cols="4" class="pa-0 pt-2 pb-6">{{ '*' + $t(headers[1].text) }}</v-col>
            <v-col>
              <v-text-field style="width: 165px;" v-model="params.userNm" clearable></v-text-field>
            </v-col>
            <v-col class="d-flex justify-end align-center mb-6">
              <v-radio-group v-model="params.sexDiv" row>
                <v-radio color="primary" v-for="(item, value) in sexList" :key="value" :label="$t(item.text)" :v-model="item.value"></v-radio>
              </v-radio-group>
            </v-col>
          </v-row>

          <v-row no-gutters class="px-2">
            <v-col cols="4" class="pa-0 pt-2 pb-6">{{ '*' + $t(headers[2].text) }}</v-col>
            <v-col>
              <v-text-field style="width: 165px;" v-model="params.userCd" clearable @input="changeValueId" />
            </v-col>
            <v-col class="d-flex justify-center mt-1">
              <v-btn
                small
                text
                color="primary"
                elevation="0"
                :disabled="isDuplication || params.compId == '' || params.userCd == '' || !regexId"
                @click="btnDuplicateConfirm()"
              >
                {{ $t('doubleCheck') }}
              </v-btn>
              <v-sheet width="22" color="transparent">
                <template v-if="isDuplication">
                  <v-icon v-if="confirmFlag == 1" size="22" color="success">mdi-check-bold</v-icon>
                  <v-icon v-else size="22" color="error">mdi-close-thick</v-icon>
                </template>
              </v-sheet>
            </v-col>
          </v-row>
          <v-row no-gutters class="px-2">
            <v-col cols="4" class="pa-0 pt-2 pb-6">{{ '*' + $t(headers[3].text) }}</v-col>
            <v-col>
              <v-text-field
                v-model="params.userPs"
                :rules="[rules.required]"
                :append-icon="show3 ? 'mdi-eye' : 'mdi-eye-off'"
                :type="show3 ? 'text' : 'password'"
                @click:append="show3 = !show3"
                clearable
              >
              </v-text-field>
            </v-col>
          </v-row>
          <v-row no-gutters class="px-2">
            <v-col cols="4" class="pa-0 pt-2 pb-6">{{ '*' + $t(headers[4].text) }}</v-col>
            <v-col>
              <v-text-field
                v-model="params.userPsConfirm"
                :rules="[rules.required]"
                :append-icon="show2 ? 'mdi-eye' : 'mdi-eye-off'"
                :type="show2 ? 'text' : 'password'"
                @click:append="show2 = !show2"
                clearable
              >
              </v-text-field>
            </v-col>
          </v-row>
          <v-row no-gutters class="px-2">
            <v-col cols="4" class="pa-0 pt-2 pb-6">{{ '*' + $t(headers[5].text) }}</v-col>
            <v-col>
              <v-text-field
                v-model="params.hpNo"
                :rules="[rules.phoneMatch]"
                hide-details
                clearable
                :placeholder="$t('phonePlaceholder')"
              ></v-text-field>
            </v-col>
          </v-row>
          <v-row no-gutters class="px-2 pb-4">
            <v-col>
              <v-radio-group v-model="params.hireGubn" class="d-flex align-center mt-4 pl-3" row>
                <v-radio color="radio" v-for="(item, index) in employmentList" :key="index" :label="item.minorNm" v-model="item.minorCd"></v-radio>
              </v-radio-group>
            </v-col>
          </v-row>
        </div>
      </div>

      <v-card-actions class="mt-6 px-8">
        <v-spacer></v-spacer>
        <v-btn small text outlined height="35" width="70" class="mr-1" color="primary" @click="close()"> {{ $t('btnClose') }} </v-btn>
        <v-btn small text outlined height="35" width="70" class="popBtn2" style="background-color: #3b50e2; color: white;" @click="onApproval">
          {{ $t('btnApprovalRequest') }}
        </v-btn>
        <v-dialog v-model="okDialog" persistent max-width="290">
          <v-card class="pa-4">
            <v-card-title class="text-subtitle-1 font-weight-bold pb-0 primary--text">
              {{ $t('confirmApprovalRequest') }}
            </v-card-title>
            <v-card-text class="pa-0 pl-6 mb-4">{{ $t('msgConfirmApprovalRequest') }}</v-card-text>
            <v-card-actions>
              <v-spacer></v-spacer>
              <v-btn small text outlined height="35" width="70" class="mr-1" color="primary" @click="okDialog = false">
                {{ $t('btnCancel') }}
              </v-btn>
              <v-btn small text outlined height="35" width="70" class="popBtn2" style="background-color: #3b50e2; color: white" @click="save()">
                {{ $t('btnConfirm') }}
              </v-btn>
            </v-card-actions>
          </v-card>
        </v-dialog>
      </v-card-actions>
    </v-card>
  </div>
</template>

<script>
import notify from 'devextreme/ui/notify'
import { AesEncrypt } from '@/utils/aes256' //cyrptojs 적용(aes256)
import { validUserName, validTell } from '@/utils/validate.js'
import { getLoginCommon, getUserListInfo, getDuplicateConfirm, savePrivateUser } from '@/api/system/userManage'
import { getMemberApproval, saveMemberApproval, deleteMemberApproval } from '@/api/baseManage/memberApprovalManage'
import { error } from 'jquery'
import sessionStore from '@/utils/sessionStore'
import { getCompId, setCompId } from '@/utils/token'

export default {
  // mixins: [baseview], //20220414 LYJ base page 추가 및 권한 처리
  name: 'i-user_info',
  components: {},
  props: {},
  data() {
    return {
      options: {
        penColor: '#c0f'
      },
      userInfo: {},
      refreshKey: 0,
      params: {
        compId: getCompId(),
        userCd: '',
        userNm: '',
        hpNo: '',
        userPs: '',
        userPsConfirm: '',
        sexDiv: 0,
        hireGubn: 'permanent'
      },
      okDialog: false,
      show1: false,
      show2: false,
      show3: false,
      error: '',
      selectedRows: [],
      dataSource: [],
      headers: [
        { value: 'compId', text: 'compCode' },
        { value: 'userNm', text: 'name' },
        { value: 'userCd', text: 'ID' },
        { value: 'userPs', text: 'password' },
        { value: 'userPsConfirm', text: 'passwordConfirm' },
        { value: 'hpNo', text: 'phone' }
      ],
      sexList: [
        { text: 'male', value: '남' },
        { text: 'female', value: '여' }
      ],
      employmentList: [],
      confirmFlag: 0,
      saveFlag: 0,
      phonePattern: /^(\d{2}||\d{3})-(\d{4}||\d{3})-\d{4}$/i,
      emailPattern: /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/g,
      rules: {
        required: value => !!value || 'Required.',
        min: v => v.length >= 8 || 'Min 8 characters',
        emailMatch: () =>
          (this.params.email != '' && this.params.email != undefined && this.params.email.match(this.emailPattern) == true) ||
          this.$t('msgInvalidEmailFormat'),
        phoneMatch: () => (this.params.hpNo != '' && this.params.hpNo != undefined && validTell(this.params.hpNo)) || this.$t('msgInvalidPhoneFormat')
      },
      regexId: false, // 아이디 유효성 검사 체크,
      duplicationFlag: true, // 다중 요청 방지
      duplicationId: '' // 중복 성공시 해당 계정과 추가로 변경할 계정 확인을 위함,
    }
  },
  beforeMount() {
    Promise.all([getLoginCommon({ majorCd: 'C0074', compId: 'IGNS' })]).then(response => {
      let failedResponse = response.find(element => !element.success)
      if (failedResponse == null) {
        //	위험성평가 조직역할 조회조건
        this.employmentList = response[0].list.slice()
      }
    })
  },
  computed: {
    datasource() {
      return this.userInfo
    },
    isDuplication() {
      if (this.duplicationId !== this.params.compId + '_' + this.params.userCd) {
        this.duplicationId == ''
      }
      return this.duplicationId == this.params.compId + '_' + this.params.userCd && this.duplicationId !== '' && this.regexId
    },
    toastSvg() {
      return this.$store.state.app.vToastifySvg
    }
  },
  mounted() {},
  activate() {},
  methods: {
    onApproval() {
      setCompId(this.params.compId)
      this.error = ''
      //유효성 검사
      var valid = ''

      if (
        this.params.compId == '' ||
        this.params.compId.trim() == '' ||
        this.params.userNm == '' ||
        this.params.userNm.trim() == '' ||
        this.params.userCd == '' ||
        this.params.userCd.trim() == '' ||
        this.params.userPs == '' ||
        this.params.userPs.trim() == '' ||
        this.params.userPsConfirm == '' ||
        this.params.userPsConfirm.trim() == '' ||
        this.params.hpNo == '' ||
        this.params.compId.trim() == '' ||
        this.params.hireGubn == ''
      ) {
        this.error = this.$t('msgfilloutAllInfo')
        return
      }

      if (!validUserName(this.params.userNm)) {
        this.error = this.$t('msgNameValidation')
        return
      }

      //입력시에는 올바른 형식으로 입력할 수 있도록
      if (this.params.hpNo == '' || this.params.hpNo == undefined || this.params.hpNo == null || this.params.hpNo.match(this.phonePattern) == null) {
        valid = 'Invalid_hpNo'
      } else if (
        !(this.params.email == '' || this.params.email == undefined || this.params.hpNo == null) &&
        this.params.email.match(this.emailPattern) == null
      ) {
        valid = 'Invalid_email'
      }

      if (this.params.sexDiv == 0) {
        this.params.sexDiv = '남'
      } else {
        this.params.sexDiv = '여'
      }

      if (this.confirmFlag === 0 && !this.isDuplication) {
        this.error = this.$t('msgChkIDDuplication')
        return
      }

      //패스워드 패스워드 확인 값비교
      if (this.params.userPs !== this.params.userPsConfirm) {
        this.error = this.$t('msgPwNotMatch')
        return
      }

      if (valid != '') {
        if (valid == 'Invalid_hpNo') {
          this.error = this.$t('msgInvalidPhoneFormat')
        } else if (valid == 'Invalid_email') {
          this.error = this.$t('msgInvalidEmailFormat')
        }
        return
      }
      this.okDialog = true
    },
    async save() {
      let params = {
        compId: this.params.compId,
        userNm: this.params.userNm,
        userCd: this.params.userCd,
        hpNo: this.params.hpNo,
        userPs: AesEncrypt(this.params.userPs),
        userPsConfirm: AesEncrypt(this.params.userPsConfirm),
        hireGubn: this.params.hireGubn,
        sexDiv: this.params.sexDiv,
        __created__: true
      }
      await saveMemberApproval([params], false)
        .then(res => {
          if (res.success) {
            this.refreshKey += 1
            notify(this.$t('msgApprovalSuccess'), 'success', 1500)
            this.close()
          } else this.error = res.msg
        })
        .catch(error => {
          if (error.response && error.response.data) {
            if (error.response.data.code == -6011) {
              this.$vToastify.prompt({ body: error.response.data.msg, answers: { 확인: true } })
            }
          }
        })
        .finally(() => {
          this.okDialog = false
        })
    },
    btnDuplicateConfirm() {
      let searchParams = { userCd: this.params.compId + '_' + this.params.userCd }
      if (!this.isDuplication && this.duplicationFlag) {
        this.duplicationFlag = false
        this.$nextTick(() => {
          if (this.params.userCd.trim().length !== 0 || this.params.userCd != '') {
            getDuplicateConfirm(searchParams)
              .then(res => {
                if (res.list === undefined) {
                  this.$vToastify.prompt({ body: this.$t('msgUsableId'), icon: this.toastSvg.success, answers: { 확인: true } })
                  this.confirmFlag = 1
                } else {
                  this.$vToastify.prompt({ body: this.$t('msgAlreadyUseId'), icon: this.toastSvg.error, answers: { 확인: true } })
                  this.confirmFlag = 0
                }
              })
              .finally(() => {
                this.duplicationId = searchParams.userCd
              })
          } else {
            this.$vToastify.prompt({ body: this.$t('msgInsertId'), answers: { 확인: true } })
          }
        })
        this.error = ''
        setTimeout(() => {
          this.duplicationFlag = true
        }, 1000)
      }
    },
    changeValueId() {
      this.confirmFlag = 0
      this.duplicationId = ''
      const regex = /^[a-zA-Z0-9_]+$/.test(this.params.userCd)
      if (!regex && this.params.userCd !== '') {
        // 입력값이 영어가 아닌 경우 수정
        this.params.userCd = this.params.userCd.replace(/[^a-zA-Z0-9_]+/g, '')
        this.error = this.$t('msgIdValidation')
        this.okDialog = false
        this.regexId = false
      } else {
        this.error = ''
        this.regexId = true
      }
    },
    changeValueComp() {
      this.confirmFlag = 0
    },
    close() {
      this.userInfo = []
      this.params = {}
      this.duplicationId = ''
      this.duplicationFlag = true
      this.regexId = false
      this.error = ''
      this.$emit('popupClose')
    }
  }
}
</script>

<style lang="scss" scoped>
//정보변경 스타일 적용 start [[
.theme--light.v-card {
  background-color: #fff !important;
}

.container {
  width: 100%;
  padding: 8px 16px;
}

.buttons {
  display: flex;
  gap: 8px;
  justify-content: center;
  margin-top: 8px;
}

.theme--light.v-data-table:not(.innerGrid)
  > .v-data-table__wrapper
  > table
  > tbody
  > v-row
  > td:hover:not(.v-data-table__expanded__content):not(.v-data-table__empty-wrapper) {
  background: #f1f3fe !important;
}

//회원가입 레이아웃
.popup-card {
  width: 480px;
  height: 280px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.popup-content {
  flex-grow: 1;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  padding: 10px;
}

.popup-content table {
  width: 100%;
}

.popup-content td {
  padding: 4px;
}

.v-text-field {
  padding: 0 !important;
  margin: 0 !important;
}
</style>
