import loginMockupData from './mock/login.json' // restful api를 사용하지 않을 경우
import request from '@/utils/request'
import { isUseAPI } from '@/utils/check'
import { getRefreshToken } from '@/utils/token'

export function loginByPassword(userInfo) {
  let apitest = true
  if (!isUseAPI() && apitest) {
    return new Promise(function (resolve, reject) {
      let res = loginMockupData[userInfo.usercd]
      let pw = loginMockupData[userInfo.usercd].userps
      res.success = true
      if (res && pw === userInfo.userps) {
        resolve(res)
      } else {
        var error = { code: '401' }
        reject(error)
      }
    })
  }
  return request({
    url: '/com/loginByPassword',
    method: 'post',
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: userInfo,
    meta: {
      useErrorMessage: false,
      useTokenUpdate: true,
      apiVersion: '1.0.0'
    }
  }).catch(error => {
    let code = error.response.status
    let msg = null
    if (!error.response.data.msg && error.response.status == 500) {
      msg = '서버와의 연결이 불안정합니다.'
    }
    else if (!error.response.data.msg) {
      msg = error.response.statusText
    }
      
    const RESULT = {
          result: false,
          code : !error.response.data.msg ? code : error.response.data.code,
          msg: !error.response.data.msg ? msg : error.response.data.msg
    };
    throw RESULT;
  })
}
export function loginPermissionCheck(userInfo) {
  return request({
    url: '/com/loginPermissionCheck',
    method: 'post',
    meta: { apiVersion: '1.0.0'},
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: userInfo
  })
}

export function getUser(usercd) {
  let apitest = false
  if (!isUseAPI() && apitest) {
    // restful api를 사용하지 않을 경우 login.json에 등록된 계정만 가져온다.
    return new Promise(function(resolve, reject) {
      // local에서는 token 값에 usercd 넣는다.
      let res = loginMockupData[usercd]
      if (res) {
        resolve(res) // 기존 토큰 값 있는 여부 확인
      } else {
        var error = { code: '401' }
        reject(error)
      }
    })
  }

  return request({
    url: '/com/getUser',
    method: 'post',
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: {
      usercd: usercd
      // domainCd: domainCd //도메인 처리 우선 막음 LYJ
    },
    meta: { apiVersion: '1.0.0' }
  })
}

export function logout() {
  return new Promise(function(resolve, reject) {
    resolve()
  })
}

export function reissueToekn(tokenInfo) {
  let userRefreshToken = getRefreshToken()
  return request({
    url: '/com/reissueToekn',
    method: 'post',
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: {
      usercd: tokenInfo.usercd,
      refreshToken: userRefreshToken
      //domainCd: tokenInfo.domainCd
    },
    meta: {
      useErrorMessage: true,
      useTokenUpdate: true,
      apiVersion: '1.0.0'
    }
  })
}
