import request from '@/utils/request'

//조회
export function getMemberApproval(searchParams, isNotify) {
  return request({
    url: `/api/getMemberApproval`,
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json' },
    data: searchParams,
    Notify: { use: isNotify, apitype: 'searched' }
  })
}
