import getAuthGroupData from '../setting/mock/getAuthGroup.json' // restful api를 사용하지 않을 경우
import request from '@/utils/request'
import { isUseAPI } from '@/utils/check'
// 공통코드 조회
// param : majorCd 만 넣어준다. ex) getCommonCode("C0004")
export function getCommonCode(param) {
  let isTest = false
  let params = {
    majorCd: param
  }

  if (!isUseAPI() || isTest) {
    return new Promise(function(resolve, reject) {
      let res = getAuthGroupData
      resolve(res.msg)
    })
  }
  return request({
    url: '/api/getCommonCode',
    method: 'POST',
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: params,
    meta: { apiVersion: '1.0.0' }
  })
}
