//#region 공통 import------------------------------------------------------------------------------------------------------------------------------------

import Vue from 'vue'
import App from './App.vue'
import store from './store/index'
import router from './router'


// 전역 설정
import envs from '@/envs'
import Cookies from 'js-cookie'
import Layout from '@/layout/layout.vue'

import { getProgramData } from '@/api/setting/programManage'
import { getAuthMenuRouteById } from '@/api/common/menu'
import sessionStore from '@/utils/sessionStore'

//toastify
import VueToastify from 'vue-toastify'
// vuescroll 추가
// import vuescroll from 'vue-scroll'
import './assets/icons' // icon



Vue.use(VueToastify, {
  position: 'center-center',
  canTimeout: false,
  theme: 'light',
  iconEnabled: true,
  withBackdrop: true
})
Vue.prototype.$envs = envs
Vue.prototype.$Cookies = Cookies
Vue.prototype.$EventBus = new Vue()

// 전역 설정 배열 조작
import _ from 'lodash'
Vue.prototype.$_ = _


//Devextreme
import 'devextreme/dist/css/dx.common.css'
import 'devextreme/dist/css/dx.light.css'
import 'devexpress-diagram/dist/dx-diagram.css'

//Devextreme Grid default setting
import '@/components/options/dxEnvs.js'

// Devextreme 언어 설정
import { locale } from 'devextreme/localization'



// 콘솔 경고 메시지 false 표시안함
Vue.config.productionTip = false


// vuetify theme loading
import vuetify from '@/plugins/vuetify'

// icon
import './assets/icons'


// i18n
import VueI18n from 'vue-i18n'
import messages from '@/i18n'
Vue.use(VueI18n)
export const i18n = new VueI18n({
  locale: 'ko', // set locale
  fallbackLocale: 'en',
  messages, // set locale messages
  silentTranslationWarn: true // 언어등록을 안함으로써 뜨는 경고를 제거하기위해 경고를 없앰
})

//#endregion 공통 import

//#region (Extra) 개발자 프로젝트별 필요 import------------------------------------------------------------------------------------------------------------

import VueDaumPostcode from 'vue-daum-postcode'
Vue.use(VueDaumPostcode, { scriptUrl: '//t1.daumcdn.net/mapjsapi/bundle/postcode/prod/postcode.v2.js' })


import VueSignature from "vue-signature-pad";
Vue.use(VueSignature);

// draggable
import { Draggable } from 'draggable-vue-directive'
Vue.use({
  install(Vue, options) {
    Vue.directive('draggable', Draggable)
  }
})

//v-mask
import { VueMaskDirective } from 'v-mask'
Vue.directive('mask', VueMaskDirective)

// echart 라이브러리 및 테마 로딩
import '@/assets/theme/echart/index.js'



//20220701 LYJ 에러 발생시 처리
Vue.config.errorHandler = (err, vm, info) => {
  // err: error trace
  // vm: component in which error occured
  // info: Vue specific error information such as lifecycle hooks, events etc.
  let fail = document.getElementById('systemBar')

  if (fail != null) {
    //console.log('fail1', fail.outerHTML)
    fail.outerHTML =
      '<div style="height:24px !important;" class="v-system-bar v-system-bar--lights-out theme--dark red lighten-1" id="systemBar">' +
      '<i aria-hidden="true" class="v-icon notranslate mdi mdi-play theme--dark"></i>데이터 처리 중 오류가 발생하였습니다. 새로고침 후 다시 시도 바랍니다.' +
      '<div class="spacer"></div><button type="button" class="pa-0 v-btn v-btn--icon v-btn--round theme--dark v-size--x-small" ' +
      "onclick=\"document.getElementById('systemBar').style.height ='0px'\">" +
      '<span class="v-btn__content">' +
      '<i aria-hidden="true" class="v-icon notranslate mdi mdi-close theme--dark"></i></span></button></div>'
    console.error(err.stack)
  }

}

// 에너지 저작도구
/** ✏️ Vue smart widget */
import VueSmartWidget from 'vue-smart-widget'
Vue.use(VueSmartWidget)

/** ✏️ Vue Konva */
import VueKonva from 'vue-konva';
Vue.use(VueKonva)


//#endregion (Extra) 개발자 프로젝트별 필요 import



//#region Vue 생성/ mount------------------------------------------------------------------------------------------------------------------------------------

//20220323 BY LYJ [동적 라우팅 처리] --> 20240717 menu.js로 이동
let vm = new Vue({
  router,
  store,
  vuetify,
  i18n,
  
  data() {
    return { ExceptionError: '' }
  },
  methods: {
    
  },
  created () {
    // 세션 스토리지로부터 locale 정보를 가져옴
    if(sessionStore.get('locale')){
      i18n.locale=sessionStore.get('locale')
    }
    locale(this.$i18n.locale)
  },
  render: h => h(App)
}).$mount('#app')

//#endregion Vue 생성/ mount------------------------------------------------------------------------------------------------------------------------------------
