<template>
  <div>
    <div class="d-flex align-center justify-space-between">
      <v-menu offset-y min-width="160">
        <template v-slot:activator="{ on }">
          <v-btn icon v-on="on" class="mr-4 align-center">
            <div class="d-flex align-center">
              <v-icon style="height: 1.5rem !important;color:white">mdi-web</v-icon>
              <div class="pr-4 app_bar_title--text text-h7">{{ dict[locale] }}</div>
            </div>
          </v-btn>
        </template>
        <v-list class="text-center">
          <v-row justify="center">
            <v-col>
              <div
                depressed
                rounded
                text
                class="pa-1"
                color="px-3 text-subtitle-2"
                style="cursor: pointer"
                v-for="(lang, index) in langs"
                :key="index"
                @click="langClick(lang.id)"
              >
                <v-divider class="my-1"></v-divider>
                {{ lang.name }}
                <img :src="lang.image" height="20px" />
              </div>
            </v-col>
          </v-row>
        </v-list>
      </v-menu>
    </div>
  </div>
</template>
<script>
import sessionStore from '@/utils/sessionStore'
import { locale } from 'devextreme/localization'
import { setCookieIocale, getCookieIocale } from '@/utils/token'
export default {
  name: 'iLange',
  components: {},
  data() {
    return {
      locale: '',
      dict: {
        ko: '한국어',
        en: 'ENG'
      },

      langs: [
        {
          id: 'ko',
          name: '한국어',
          image: require('@/assets/images/flags/ko.png')
        },
        {
          id: 'en',
          name: 'English',
          image: require('@/assets/images/flags/en.png')
        }
      ]
    }
  },
  mounted() {
    this.locale = sessionStore.get('locale')
    //자동 로그인시(session locale없을때) cookie locale 사용
    if (this.locale == null || getCookieIocale() != null) {
      this.locale = getCookieIocale()
      this.$i18n.locale = this.locale
      locale(this.$i18n.locale)
    } else {
      this.locale = 'ko'
    }
  },
  computed: {},
  methods: {
    // 버튼 클릭 시 각 id별로 이벤트생성
    langClick(lang) {
      this.locale = lang
      sessionStore.set('locale', lang)
      this.$i18n.locale = lang
      locale(this.$i18n.locale)

      //locale cookie setting
      setCookieIocale()
    }
  }
}
</script>

<style lang="scss" scoped></style>
