import request from '@/utils/request'

//조회
export function getUserList(isNotify) {
  return request({
    url: `/api/getUserList`,
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json' },
    Notify: { use: isNotify, apitype: 'searched' }
  })
}

