export function getUserListInfo(searchParams) {
  let isTest = false
  let data =searchParams
  if (isTest) {
    return new Promise(function(resolve, reject) {
      let response = { list: [] }
      userListInfo.list.forEach(item => {
        if(item.userCd === searchParams || searchParams == null)
        response.list.push(item)
      })
      resolve(response)
    })
  }
  return request({
    url: `/api/getUserListInfo`,
    method: 'POST',
    meta: { apiVersion: '1.0.0' },
    headers: { 'Content-Type': 'application/json' },
    data : searchParams
  })
}
