import getMenuOfgroupManageData from './mock/getMenuOfgroupManage.json' // restful api를 사용하지 않을 경우
import request from '@/utils/request'
import { isUseAPI } from '@/utils/check'


// 권한그룹별 메뉴 조회
export function getMenuOfgroupManage(param, isNotify) {
  let isTest = false;

  if (!isUseAPI() || isTest) {
    return new Promise(function(resolve, reject) {
      let res = getMenuOfgroupManageData
      resolve(res.msg)      
    })
  }
  return request({
    url: '/api/getMenuOfgroupManage',
    method: 'POST',
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: param,
    meta: { apiVersion: '1.0.0' },
    Notify: { use: isNotify, apitype: 'searched' } //searched, saved,deleted
  })
}

// 권한그룹별 메뉴 저장
export function saveMenuOfgroupManage(param, isNotify) {
  let isTest = false;

  if (!isUseAPI() || isTest) {
    return new Promise(function(resolve, reject) {
      let res = getMenuOfgroupManageData
      resolve(res.msg)      
    })
  }
  return request({
    url: '/api/saveMenuOfgroupManage',
    method: 'POST',
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: param,
    meta: { apiVersion: '1.0.0' },
    Notify: { use: isNotify, apitype: 'saved' } //searched, saved,deleted
  })
}
