<template>
  <v-app>
    <TopBar :menuTree="menuTree" :companyInfo="companyInfo" :userGrp="userGrp" @refresh="refresh"/>
    <div class="mainBackground">
      <totalMenu :menuTree="menuTree" v-if=""></totalMenu>
      <div id="mainContent" :class="isDashboard">
        <keep-alive :key="key" v-if="showComponent">
          <router-view ref="componentRef" />
        </keep-alive>
      </div>
    </div>
    <Footer :companyInfo="companyInfo"></Footer>
    <VueToastify :notifyAction="notifyAction"></VueToastify>
              
  </v-app>
</template>

<script>
import TopBar from '@/layout/TopBar.vue';
import totalMenu from '@/layout/totalMenu.vue'
import Footer from '@/layout/Footer.vue';
import { getUserCd,getCompId } from '@/utils/token';
import { getGrpAuth } from '@/api/common/commonApi'
import { getCompanyInfo } from '@/api/dashboard/dashboard.js'
import VueToastify from '@/components/toastify/VueToastify.vue'


export default {
  name: 'Layout',
  components: {
    TopBar,
    totalMenu,
    Footer,
    VueToastify
  },
  data: ()=>({
    companyInfo:{},
    userGrp:[],
    showComponent:true
  }),
  computed:{
    key() {
        return this.$route.path
    },
    menuTree() {
      let usercode = getUserCd()
      if (this.$store.state.menu.treeMenus.length == 0) {
        this.$store.dispatch('GetMenus', { usercd: usercode })
      }
      return _.orderBy(this.$store.state.menu.treeMenus, 'sort', 'asc')
    },
    
    isDashboard() {
      if (this.$route.name == 'dashboard') return 'dashboard'
      return ''
    },
  },
  methods:{
    refresh() {
      this.showComponent = false;
      this.$nextTick(() => {
        this.showComponent = true;
      });
    },
    notifyAction(notifyInfo, action) {
      this.$EventBus.$emit(`${this.$route.query.selMenuid}_notifyAction`, { notifyInfo: notifyInfo, action: action })
    },
  },
  beforeMount() {
    Promise.all([getCompanyInfo({ compId: getCompId()}, false), getGrpAuth()]).then(res => {
      this.companyInfo = res[0].list[0]
      this.userGrp = res[1].list
    })
  }

}
</script>
<style lang="scss" scoped>
  .mainBackground{
    display: flex;
    padding-top: 88px;
    background: #43637C;
  }
  #mainContent{
    border-radius: 40px 0 0 40px;
    min-height: calc(100vh - 110px);
    background: #EEF2F5;
    &:not(.dashboard){
      background: #fff;
      padding: 8px 12px;
    } 
  }
  
</style>
