import store from '@/store'
import router from '@/router'
import { loginByPassword } from '@/api/common/login'
import { AesEncrypt, AesDecrypt } from '@/utils/aes256' //cyrptojs 적용(aes256) by lyj 20220404
import envs from '@/envs'
/*
 * 로그인을 위한 함수 정의
 */

// 자동 로그인 체크
export function fn_AutoLogin() {
  return Boolean(sessionStorage.getItem('isAutoLogin'))
}

// 로그인
// [Object] userData (usercd, userps, isAutoLogin)
export function fn_Login(userData) {
  return new Promise(function(resolve, reject) {
    const RESULT = {
      result: false,
      msg: '사용자 정보를 입력해주세요.'
    }
    // 로딩 시작 함수 만들기
    if (!userData.compId || userData.compId.trim() === '') {
      RESULT.result = false
      RESULT.msg = '기업코드를 입력해주세요.'
      return resolve(RESULT)
    }
    if (!userData.usercd || userData.usercd.trim().split('_')[1] === '') {
      RESULT.result = false
      RESULT.msg = '사용자 아이디를 입력해주세요.'
      return resolve(RESULT)
    }
    if (!userData.userps || userData.userps.trim() === '') {
      RESULT.result = false
      RESULT.msg = '비밀번호를 입력해주세요.'
      return resolve(RESULT)
    }

    const userInfo = {
      usercd: userData.usercd,
      userps: AesEncrypt(userData.userps),
      lastLoginOs: 'WEB',
      isAutoLogin: userData.isAutoLogin,
      compId: userData.compId
    }

    loginByPassword(userInfo)
      .then(login_res => {
        if (login_res.success) {
          return store.dispatch('LoginByPassword', { userInfo, login_res })
            .then(() => store.dispatch('SetUserInfo', { usercd: userData.usercd }))
            .then(() => store.dispatch('GetMenus', { usercd: userData.usercd }))
            .then(() => {
              RESULT.result = true;
              RESULT.msg = login_res.msg;
              resolve(RESULT);
            });
        } else {
          RESULT.msg = login_res.msg;
          resolve(RESULT);
        }
      })
      .catch((e) => {
        RESULT.msg = e.msg;
        resolve(RESULT);
      });
  });
}

