<template>
  <div class="toastify">
    <DxLoadPanel
      :key="`panel${key}`"
      :position="position"
      :visible="loadingVisible"
      :show-indicator="showIndicator"
      :show-pane="showPane"
      :shading="true"
      :close-on-outside-click="closeOnOutsideClick"
      :on-shown="onShown"
      shading-color="rgba(0,0,0,0.0)"
      message=""
    />
  </div>
</template>

<script>
import DxLoadPanel from 'devextreme-vue/load-panel'
import { custom } from 'devextreme/ui/dialog'
// import { DxPopup, DxPosition, DxToolbarItem } from 'devextreme-vue/popup'
export default {
  name: 'VueToastify',
  components: {
    DxLoadPanel,
    custom
    //DxPopup, DxPosition, DxToolbarItem
  },
  props: {
    notifyAction: { type: Function, required: true, default: () => {} }
  },

  watch: {},
  data() {
    return {
      //dxLoadPanel
      loadingVisible: false,
      showIndicator: true,
      showPane: false,

      closeOnOutsideClick: false,
      position: { of: '.container' },
      //popup
      notifyInfo: {},
      key: 0
    }
  },
  created() {},
  mounted() {
    console.log('VueToastify mounted')
    // this.$EventBus.$off('openLoading')
    // this.$EventBus.$off('endLoading')
    // this.$EventBus.$off('popupNotify')

    this.$EventBus.$on('openLoading', x => {
      //console.log('openLoading 2')
      this.forceRerender()
      if (x == 'popup') {
        this.position = { of: '#gridBolck' }
      } else {
        this.position = { of: '.container' }
      }
      this.loadingVisible = true
    })
    this.$EventBus.$on('endLoading', x => {
      //console.log('endLoading 2')
      this.loadingVisible = false
    }),
      this.$EventBus.$on('popupNotify', x => {
        console.log('VueToastify event popupNotify on ', x)
        //common
        this.notifyInfo.messageType = x.messageType
        this.notifyInfo.currentMsg = x.body
        this.notifyInfo.useLoding = x.useLoding
        let buttons = []

        if (x.popupType == 'yesno') {
          this.notifyInfo.yesAction = x.yesAction
          this.notifyInfo.noAction = x.noAction
          buttons = [
            {
              text: this.$t('btnYes'),
              onClick: e => {
                return { buttonText: e.component.option('text'), btnType: 'yes' }
              }
            },
            {
              text: this.$t('btnNo'),
              onClick: e => {
                return { buttonText: e.component.option('text'), btnType: 'no' }
              }
            }
          ]
        } else if (x.popupType == 'confirm') {
          this.notifyInfo.confirmAction = x.confirmAction
          buttons = [
            {
              text: this.$t('ok'),
              onClick: e => {
                return { buttonText: e.component.option('text'), btnType: 'confirm' }
              }
            }
          ]
        }
        //icon
        //이서씨 클래스 작업 부탁합니다.
        //messageType : info, error, warn, question
        let iconClass = 'toastify' + x.messageType + 'Class'
        let myDialog = custom({
          showTitle: false,
          // title: x.title,
          messageHtml: '<div class="' + iconClass + '">' + x.body + '</div>',
          buttons: buttons
        })
        if (x.body == '') {
          if (x.popupType == 'yesno') this.notifyAction(this.notifyInfo, this.notifyInfo.yesAction)
          else if (x.popupType == 'confirm') this.notifyAction(this.notifyInfo, this.notifyInfo.confirmAction)
        } else {
          myDialog.show().then(dialogResult => {
            this.notifyInfo.btnType = dialogResult.btnType
            if (dialogResult.buttonText == this.$t('btnYes')) {
              this.notifyAction(this.notifyInfo, this.notifyInfo.yesAction)
            } else if (dialogResult.buttonText == this.$t('btnNo')) {
              this.notifyAction(this.notifyInfo, this.notifyInfo.noAction)
            } else if (dialogResult.buttonText == this.$t('ok')) {
              this.notifyAction(this.notifyInfo, this.notifyInfo.confirmAction)
            }
          })
        }
      })
  },
  computed: {},
  activated() {
    ////console.log('activated')
  },
  methods: {
    forceRerender() {
      this.key += 1
    },
    onShown() {
      // setTimeout(() => {
      //   this.loadingVisible = false
      // }, 3000)
    }
  },
  beforeDestroy() {
    this.$EventBus.$off('openLoading')
    this.$EventBus.$off('endLoading')
    this.$EventBus.$off('popupNotify')
  }
}
</script>

