import Vue from 'vue'
import VueRouter from 'vue-router'
import envs from '@/envs'

import Layout from '@/layout/layout.vue'
import Login from '@/layout/login/Login.vue'
import CallbackNaverLogin from '@/layout/login/CallbackNaverLogin.vue'
import Logout from '@/layout/login/Logout'
import NotFound from '@/views/error/404'

import dashboard from '@/views/dashboard/Dashboard'
import inspection from '@/views/error/inspection' //점검중
import preparing from '@/views/error/preparing' //준비중

import {
  getCookieAutoLogin,
  getCookieCompId,
  getCookieToken,
  getCookieUserCd,
  getToken,
  setToken,
  setUserCd,
} from '@/utils/token'
import { loginPermissionCheck } from '@/api/common/login'
import store from '@/store'

Vue.use(VueRouter)

let router = createRouter()

function createRouter(){
 return new VueRouter({
   mode: 'hash',
   routes: [
     {
       path: '/',
       redirect: '/login',
       component: Layout,
       children: [
         {
           path: '/dashboard',
           name: 'dashboard',
           // query: { tMenu: '1000', lvl: 0 },
           // params: {
           //   tMenu: '1000', lvl: 0
           // },
           component: dashboard
         },

         //서비스 점검중
         {
           path: '/inspection',
           name: 'inspection',
           component: inspection
         },
         //서비스 준비중
         {
           path: '/preparing',
           name: 'preparing',
           component: preparing
         }
       ]
     },
     {
       path: '/login/naver',
       name: 'naver',
       component: CallbackNaverLogin
     },
     {
       path: '/login',
       name: 'login',
       component: Login
     },
     {
       path: '/logout',
       name: 'logout',
       component: Logout
     },
    //  {
    //    path: '*', // 모든 경로를 처리
    //    name: 'not-found',
    //    component: NotFound // 404.vue 컴포넌트를 연결
    //  }
   ]
 })
 

}

export function resetRouter() {
  const newRouter = createRouter();
  router.matcher = newRouter.matcher; // 기존 라우터의 매처를 새로운 라우터의 매처로 교체합니다.
}

import { getUserCd } from '@/utils/token';
router.beforeEach(function(to, from, next) {
  //console.log('----beforeEach---------')
  if (!to.matched.length) {
    // 새로고침 시 동적 라우팅 정보가 초기화 됨
    // Login 처리가 되어 Token 정보를 가지고 있다면 route 및 메뉴 정보 재조회
    if (getToken()){
      let param = {
        usercd: getUserCd()
      }
      store.dispatch('GetMenus', param)
    }
    next() //20220324 LYJ Missing router information on page refresh in vue
  } else {
    let loginWhiteList = [...envs.framework.whiteList]
    // 세션 적용 되면 이곳 로직 변경
    if (
      !loginWhiteList.some(path => {
        return path === to.path
      })
    ) {
      if (to.query.id) {
        console.log('단독 페이지호출시 next(/login)되던것을 막음')
      } else {
        if (!getToken() && to.path !== '/login') {
          next('/login')
          return
        } else {
          if (!getToken() && to.path !== '/blank' && to.path !== '/not-found') {
            next('/blank')
            return
          }
        }
      }
    }
    try {
      //토큰이 있는 경우에는 로그인페이지가 대시보드 페이지로 이동되도록 수정함 20220517 LYJ
      if (getToken() && to.path === '/login') {
        next('/dashboard')
      } else if (getCookieToken() && to.path === '/login' && getCookieAutoLogin()) {
        setToken(getCookieToken()) // 인증을 위한 token 값 입력        
        setUserCd(getCookieUserCd()) // 인증을 위한 userCd 값 입력 

        let param = {
          usercd: getCookieUserCd(),
          compId: getCookieCompId(),
          lastLoginOs: 'WEB'
        }

        loginPermissionCheck(param)
          .then(login_res => {
            store.dispatch('SetUserInfo', { usercd: param.usercd })
            .then(() =>
              store.dispatch('GetMenus', { usercd: param.usercd }))
              .then(() => {
                next('/dashboard')
              })
              .catch(error => {
                console.error('Error during login sequence:', error)
                window.sessionStorage.clear()
                next('/login')
              })
          })
          .catch(error => {
            console.error('Error checking login permissions:', error)
            window.sessionStorage.clear()
            next('/login')
          })
      } else next(Error)
    } catch (error) {
      console.log(error)
    }
  }
})

/**
 * 모듈을 찾을 수 없다면 404 페이지로 이동처리
 */
router.onError(function(e) {
  if (e.code === 'MODULE_NOT_FOUND') router.push('/pageNotFound').catch(e => {})
})

