import Cookies from 'js-cookie'
import sessionStore from '@/utils/sessionStore'
import { AesDecrypt, AesEncrypt } from '@/utils/aes256'

const TokenKey = 'Token';
const RefreshTokenKey = 'RefreshToken';
const userInfoKey = 'userInfo';
const localeKey = 'locale';

//#region Session
//#region Token
export function getToken() {
  return sessionStore.get(TokenKey) != null ? sessionStore.get(TokenKey) : sessionStore.get('token');
}

export function setToken(token) {
  if (token == null) return;
  return sessionStore.set(TokenKey, token);
}
//#endregion
//#region Refresh Token
export function getRefreshToken() {
  return sessionStore.get(RefreshTokenKey);
}

export function setRefreshToken(token) {
  return sessionStore.set(RefreshTokenKey, token);
}
//#endregion
//#region User Info
export function setUserInfo(userInfo) {
  const userInfoObject = userInfo.reduce((acc, item) => {
    acc[item.id] = item.content;
    return acc;
  }, {});
  return sessionStore.set(userInfoKey, JSON.stringify(userInfoObject));
}

export function getUserInfo() {
  let userInfo = JSON.parse(sessionStore.get(userInfoKey));
  if (!userInfo) {
    // 기본값 설정 (객체 형태로 설정)
    userInfo = {
      compId: '',
      compNm: '',
      userCd: '',
      grpAuthCd: ''
    };
  }
  // Map으로 변환
  return userInfo;
}
//#endregion
//#region CompId
export function getCompId() {
  return getUserInfo().compId;
}
export function setCompId(newContent) {
  let userInfo = getUserInfo();
  userInfo.compId = newContent;
  sessionStore.set(userInfoKey, JSON.stringify(userInfo));
}
//#endregion
//#region CompNm
export function getCompNm(){
  return getUserInfo().compNm;
}
//#endregion
//#region UserCd
export function getUserCd(){
  return getUserInfo().userCd
}
export function setUserCd(newContent) {
  const userInfo = getUserInfo()
  userInfo.userCd = newContent;
  sessionStore.set(userInfoKey, JSON.stringify(userInfo));
}
//#endregion
//#region GrpAuthCd
export function getGrpAuthCd(){
  return getUserInfo().grpAuthCd;
}
//#endregion
//#endregion

//#region Cookies

export function setCookieUserInfo(userInfo) {
  const userInfoObject = userInfo.reduce((acc, item) => {
    acc[item.id] = item.content;
    return acc;
  }, {});
  return Cookies.set(userInfoKey, AesEncrypt(JSON.stringify(userInfoObject)), { expires: 30, path: '' });
}
export function getCookieUserInfo() {
  let userInfo = Cookies.get(userInfoKey);
  if (userInfo) {
      userInfo = JSON.parse(AesDecrypt(userInfo));
  }else {
    userInfo = {
      compId: '',
      userCd: '',
      isAutoLogin: ''
    };
  }
  return userInfo;

}
//#region CompId

export function setCookieCompId(newContent) {
  const userInfo = getCookieUserInfo();
  userInfo.compId = newContent;
  const encryptedUserInfo = AesEncrypt(JSON.stringify(userInfo));
  Cookies.set(userInfoKey, encryptedUserInfo, { expires: 30, path: '' });
}
export function getCookieCompId() {
  return getCookieUserInfo().compId;
}
//#endregion
//#region Token
export function setCookieToken(token) {
  return Cookies.set(TokenKey, token, { expires: 30, path: '' });
}
export function getCookieToken() {
  return Cookies.get(TokenKey);
}
//#endregion
//#region UserCd
export function setCookieUserCd(newContent) {
  const userInfo = getCookieUserInfo();
  userInfo.userCd = newContent;
  const encryptedUserInfo = AesEncrypt(JSON.stringify(userInfo));
  Cookies.set(userInfoKey, encryptedUserInfo, { expires: 30, path: '' });
}
export function getCookieUserCd() {
  return getCookieUserInfo().userCd;
}
//#endregion
//#region AutoLogin

export function setCookieAutoLogin(newContent) {
  const userInfo = getCookieUserInfo();
  userInfo.isAutoLogin = newContent;
  const encryptedUserInfo = AesEncrypt(JSON.stringify(userInfo));
  Cookies.set(userInfoKey, encryptedUserInfo, { expires: 30, path: '' });
}
export function getCookieAutoLogin() {
  return getCookieUserInfo().isAutoLogin;
}
//#endregion
//#region remove UserCd
export function removeUserInfo() {
  const userInfo = getCookieUserInfo();
  userInfo.compId = '';
  userInfo.userCd = '';
  const encryptedUserInfo = AesEncrypt(JSON.stringify(userInfo));
  Cookies.set(userInfoKey, encryptedUserInfo, { expires: 30, path: '' });
}
//#endregion
//#region remove Token
export function removeToken() {
  removeUserInfo();
  return Cookies.remove(TokenKey);
}
//#endregion
//#region Iocale
export function setCookieIocale() {
  const encryptedData = AesEncrypt(sessionStore.get('locale'));
  Cookies.set(localeKey, encryptedData, { expires: 30, path: '' });
}
export function getCookieIocale() {
  const decryptedData = AesDecrypt(Cookies.get(localeKey));      
  return decryptedData;
}
//#endregion
//#endregion
