import Cookies from 'js-cookie'

export default {
  namespaced: true,

  //data
  state: {
    sidebar: {
      opened: Cookies.get('sidebarStatus') ? !!+Cookies.get('sidebarStatus') : true,
      withoutAnimation: false
    },
    device: 'desktop',
    size: Cookies.get('size') || 'medium',
    compId: '', //20220405 LYJ 설정 슈퍼유저일 경우 선택된 사업장코드
    compNm: '', //20220405 LYJ 설정 슈퍼유저일 경우 선택된 사업장명
    userCd: '', //20220405 LYJ 설정 슈퍼유저일 경우 선택된 사용자코드
    vToastifySvg: {
      question: `<svg viewBox="0 0 24 24" style="width: 24px; height: 24px;"><path d="M10,19H13V22H10V19M12,2C17.35,2.22 19.68,7.62 16.5,11.67C15.67,12.67 14.33,13.33 13.67,14.17C13,15 13,16 13,17H10C10,15.33 10,13.92 10.67,12.92C11.33,11.92 12.67,11.33 13.5,10.67C15.92,8.43 15.32,5.26 12,5A3,3 0 0,0 9,8H6A6,6 0 0,1 12,2Z"></path></svg>`,
      info: `<svg viewBox="0 0 24 24" style="width: 24px; height: 24px;"><path d="M10 3H14V14H10V3M10 21V17H14V21H10Z" /></svg>`,
      success: `<div class="vt-icon"><svg viewBox="0 0 24 24" style="width: 24px; height: 24px;"><path d="M9,20.42L2.79,14.21L5.62,11.38L9,14.77L18.88,4.88L21.71,7.71L9,20.42Z" /></svg>`,
      error: `<div class="vt-icon"><svg viewBox="0 0 24 24" style="width: 24px; height: 24px;"><path d="M20 6.91L17.09 4L12 9.09L6.91 4L4 6.91L9.09 12L4 17.09L6.91 20L12 14.91L17.09 20L20 17.09L14.91 12L20 6.91Z" /></svg>`,
    }
  },

  //데이터 변경시
  mutations: {
    TOGGLE_SIDEBAR: state => {
      state.sidebar.opened = !state.sidebar.opened
      state.sidebar.withoutAnimation = false
      if (state.sidebar.opened) {
        Cookies.set('sidebarStatus', 1)
      } else {
        Cookies.set('sidebarStatus', 0)
      }
    },

    CLOSE_SIDEBAR: (state, withoutAnimation) => {
      Cookies.set('sidebarStatus', 0)
      state.sidebar.opened = false
      state.sidebar.withoutAnimation = withoutAnimation
    },

    TOGGLE_DEVICE: (state, device) => {
      state.device = device
    },

    //20220405 LYJ 설정 슈퍼유저일 경우 선택된 클라이언트 아이디
    SET_SELECTED_CONFIG: (state, config) => {
      state.compId = config.compId
      state.compNm = config.compNm
    },

    SET_SIZE: (state, size) => {
      state.size = size
      Cookies.set('size', size)
    }
  },

  //methods
  actions: {
    toggleSideBar({ commit }) {
      commit('TOGGLE_SIDEBAR')
    },
    closeSideBar({ commit }, { withoutAnimation }) {
      commit('CLOSE_SIDEBAR', withoutAnimation)
    },
    toggleDevice({ commit }, device) {
      commit('TOGGLE_DEVICE', device)
    },
    //20220405 LYJ 설정 슈퍼유저일 경우 선택된 클라이언트 아이디
    setInfoForConfig({ commit }, config) {
      commit('SET_SELECTED_CONFIG', config)
    },
    setSize({ commit }, size) {
      commit('SET_SIZE', size)
    }
  },

  //computed
  getters: {}
}
