/**
 * 정규식 - 전화번호 (팩스, 일반 전화, 휴대전화 포함)
 * @param {string} str
 * @returns {Boolean}
 */
export function validTell(str) {
  const reg = /^0\d{1,2}-\d{3,4}-\d{4}$/
  return reg.test(str)
}

