<template>
    <v-app-bar app clipped-left fixed color="app_bar_bg" elevation="0" height="88" flat width="100vw" style="z-index: 1499 !important;">
      <div class="app_bar_wrap d-flex justify-space-between">
        <v-img
          :src="require(`@/assets/images/logo/logo.png`)"
          width="100%" contain max-width="225" max-height="75" class="py-2 ml-2"
          style="cursor: pointer"
          @click="goHome"
        >
        </v-img>
        <div class="d-flex justify-end align-center " style="max-width:500px;">
          <ilang/>
          <div class="user_info">
            <p class="ma-0 pa-0 text-caption pt-1" style="color:#fff; line-height:1.4;">{{ getCompNm() }}</p>
            <p class="ma-0 pa-0 pr-2 text-caption font-weight-bold" style="color:#fff; line-height:1.2; max-width:250px">
              {{ user.fullName + getGroup(user, 'layout') }} <span class="font-weight-medium">님</span>
            </p>
          </div>
          <v-menu offset-y min-width="160">
                <template v-slot:activator="{ on }">
                  <v-btn width="32" height="32" class="mr-4 mt-1" icon v-on="on" @click="clickUserInfoMenu()">
                    <svg-icon icon-class="person"></svg-icon>
                  </v-btn>
                </template>
                <v-list class="text-center" id="my-info" color="app_bar_title">
                  <v-avatar color="service" class="mb-2">
                    <span class="app_bar_title--text text-h7">{{ getGroup(user, 'popup') }}</span>
                  </v-avatar>
                  <br />
                  <span class="black--text bold" style="font-size: 0.8rem;color:gray ">{{ user.fullName }}</span>
                  <p class="text-caption mt-1">
                    {{ user.email }}
                  </p>
                  <v-divider class="my-1"></v-divider>
                  <v-row justify="center">
                    <v-dialog v-model="dialog" persistent max-width="600px">
                      <template v-slot:activator="{ on, attrs }">
                        <v-btn depressed rounded text class="px-3 text-subtitle-2 font-weight-bold" v-bind="attrs" v-on="on" @click="dialogDataLoad()">
                          {{ $t('changeInfo') }}
                        </v-btn>
                      </template>
                      <i-user-info ref="ref_iUserInfo" @onclose="userInfoDialogClose()"></i-user-info>
                    </v-dialog>
                  </v-row>
                  <v-divider class="my-1"></v-divider>
                  <v-btn depressed rounded text class="px-3" color="px-3 text-subtitle-2" @click="logout()">
                    {{ $t('logout') }}
                  </v-btn>
                  <v-divider class="my-1"></v-divider>
                  <v-btn depressed rounded text class="px-3" color="px-3 text-subtitle-2" @click="getManual()">
                    <v-icon>$info</v-icon>
                    {{ $t('help') }}
                  </v-btn>
                </v-list>
              </v-menu>
          <v-autocomplete
            v-if="isRequiredSuperConfig"
            class="ml-2"
            v-model="gridBoxValue"
            :items="gridDataSource"
            label="관리 사업장 선택"
            solo
            item-text="compId"
            item-value="compId"
            @change="onCompChanged"
          >
            <template v-slot:item="data">
              <v-list-item-content>
                <v-list-item-title v-html="data.item.compId"></v-list-item-title>
                <v-list-item-subtitle v-html="data.item.compNm"></v-list-item-subtitle>
              </v-list-item-content>
            </template>
          </v-autocomplete>
          <v-app-bar-nav-icon color="app_bar_title" class="hidden-md-and-up" @click.stop="drawer = !drawer"></v-app-bar-nav-icon>
            <v-navigation-drawer v-model="drawer" absolute color="footer_bg" dark right height="100vh" class="hidden-md-and-up">
              <v-list-item-title align="center" class="d-flex pl-5 pr-3 py-3">
                <div class="font-weight-bold text-subtitle-1 d-inline-block text-center white--text">전체메뉴</div>
                <v-spacer />
                <v-icon color="primary" class="pa-1" @click="drawer = false">$close</v-icon>
              </v-list-item-title>
              <v-divider />
              <totalMenuResponsive :menuTree="menuTree"></totalMenuResponsive>
            </v-navigation-drawer>
        </div>
      </div>
      
    </v-app-bar>
  </template>
  
  <script>
  
  import ilang from '@/components/options/iLang.vue'
  import { getCompNm,getUserCd,setCompId } from '@/utils/token'
  import { getUserList } from '@/api/system/userManage'
  import { getCompanyList } from '@/api/setting/compManage'
  import { fn_Logout } from '@/framework/login/login'
  import UserInfo from '@/layout/userInfo/UserInfo.vue'
  import { getManual } from '@/api/commonESG/commonESGApi'
  import totalMenuResponsive from '@/layout/totalMenuResponsive'

  import { downloadFile } from '@/api/baseManage/fileUpload'

  export default {
    name: 'TopBar',
    components: {
      ilang,
      totalMenuResponsive,
      'i-user-info': UserInfo
    },
    mounted(){
      this.getDataFromDB()
    },

    data() {
      return {
        user: {
          initials: 'ESG',
          fullName: 'ESG',
          email: 'yjlim@i-gns.co.kr'
        },
        dialog: false,
        drawer: false,
        gridBoxValue: '',
        isRequiredSuperConfig:false,
        gridDataSource:[]
      };
    },
    props: {
      menuTree: Array,
      companyInfo:Object,
      userGrp:Array
    },
    methods: {
      getCompNm() {
        return this.$store.state.app.compNm ? this.$store.state.app.compNm : getCompNm()
      },
      getGroup(user, type) {
        if (this.userGrp === '') return ''
        let grp = this.userGrp.find(element => {
          return element.grpAuthCd == user.initials
        })
        let nm = ''
        if (grp) {
          nm = grp.grpAuthNm
          if (type === 'layout') nm = '(' + nm + ')'
        }
        return nm
      },
      
      getDataFromDB() {
        getUserList()
          .then(res => {
            if (res.success) {
              
              //슈퍼 유저인지 여부 확인
              res.list.forEach(element => {
                if (element.userCd == getUserCd()) {
                  if (element.grpAuthCd == 'super') this.isRequiredSuperConfig = true
                  this.user.initials = element.grpAuthCd
                  this.user.fullName = element.userNm
                  this.user.email = element.email
                }
              })
              getCompanyList()
                .then(res2 => {
                  if (res2.success) {
                    this.gridDataSource = res2.list
                  }
                })
                .catch(error => {
                })
            }
          })
          .catch(error => {
          })
      },
      goHome() {
        this.$router.push('/dashboard');
      },
      clickUserInfoMenu() {
        if (this.openState) this.openState = false
      },
      dialogDataLoad() {
        if (this.$refs['ref_iUserInfo'] != undefined) this.$refs['ref_iUserInfo'].load()
      },
      userInfoDialogClose() {
        this.dialog = false;
      },
      logout() {
        fn_Logout()
      },
      getManual() {
        let grp = this.userGrp.find(element => {
          return element.grpAuthCd == this.user.initials
        })
  
        let authGrp = 'normal'
        if (grp.grpAuthCd == 'master' || grp.grpAuthCd == 'manager' || grp.grpAuthCd == 'super') authGrp = 'manager'
  
        let param = {
          authGrp: authGrp,
          device: 'web'
        }
  
        getManual(param).then(res => {
          if (res.fileId) {
            downloadFile(res.fileId).then(file => {
              let link = document.createElement('a')
              // 객체를 만들어서 생성
              let objectUrl = window.URL.createObjectURL(file)
              link.href = objectUrl
              link.download = res.fileDesc
              link.click()
            })
          }
        })
      },
      onCompChanged(value) {
        setCompId(this.gridBoxValue)
        this.$emit('refresh')
      },
    },
  };
  </script>
  
  <style lang="scss" scoped>
  .app_bar_wrap {
    width: 100%;
  }
  .user_info{
    @media (max-width: 960px) {
      display: none;
    }
  }
  </style>
  
