<template>
  <div class="userInfoChange">
    <v-card :key="refreshKey" class="pa-0">
      <v-card-title class="py-3">
        <span class="text-subtitle-2 font-weight-bold">{{ $t('changePersonalInformation') }}</span>
      </v-card-title>
      <v-divider />
      <div v-if="error != ''" class="pl-4 pt-2 pb-0" style="background: #fff;">
        <small style="color:red;"><svg-icon icon-class="error" style="height: 0.8rem!important; margin-right:4px;" />{{ error }}</small>
      </div>
      <v-card-text style="max-height:500px; overflow-y: scroll;" class="pa-4 py-0 pr-1">
        <v-row>
          <v-col cols="12" sm="6" md="6">
            <v-text-field :label="$t('userName')" :value="datasource.korNameJbrp" disabled></v-text-field>
          </v-col>
          <v-col cols="12" sm="6" md="6">
            <v-text-field :label="$t('permissionGroup')" :value="datasource.grpAuthNm" disabled></v-text-field>
          </v-col>
          <v-col cols="12" sm="6" md="6">
            <v-text-field :label="$t('phone')" v-model="datasource.hpNo" :rules="[rules.phoneMatch]"></v-text-field>
          </v-col>
          <v-col cols="12" sm="6" md="6">
            <v-text-field :label="$t('affiliatedCompany')" :value="datasource.compNm" disabled></v-text-field>
          </v-col>
          <!-- <v-col cols="12" sm="6" md="4">
            <v-text-field :label="$t('riskEvaluationRole')" :value="datasource.deptName" disabled></v-text-field>
          </v-col>
          <v-col cols="12" sm="6" md="4">
            <v-text-field :label="$t('emergencyGroup')" :value="datasource.teamName" disabled></v-text-field>
          </v-col> -->
          <v-col cols="12">
            <v-text-field label="Email" v-model="datasource.email" :rules="[rules.emailMatch]" required></v-text-field>

            <!--  편집모드일 경우 -->

            <div v-if="signature.mode == 'edit'">
              <div class="d-flex">
                <span class="mt-3 pt-2 pl-1" style="font-size: 0.66rem; color:black">{{ `${$t('signature')} (${signature.mode} mode)` }}</span>
                <div class="d-flex ml-auto mr-0 mt-3">
                  <v-btn icon class="ml-0 pa-0 mr-0" height="auto" width="80" @click="saveSign">
                    <v-icon small color="primary">mdi-check</v-icon
                    ><span style="font-size: 0.66rem; color:black">{{ $t('editingComplete') }}</span></v-btn
                  >
                  <v-btn icon class="ml-0 pa-0 mr-0" height="auto" width="80" @click="clearSign">
                    <v-icon small color="primary">mdi-pencil-off-outline</v-icon
                    ><span style="font-size: 0.66rem; color:black">{{ $t('clear') }}</span>
                  </v-btn>
                  <v-btn icon class="ml-0 pa-0 mr-0" height="auto" width="30" @click="handleSignature('display')">
                    <v-icon small color="primary">mdi-close-circle-outline</v-icon>
                  </v-btn>
                </div>
              </div>
              <VueSignaturePad id="signature" width="100%" height="156px" ref="signaturePad" />
            </div>

            <!--  디스플레이모드일 경우 -->
            <div v-else>
              <div class="d-flex">
                <span class="mt-3 pt-2 pl-1" style="font-size: 0.66rem; color:black">{{ `${$t('signature')} (${signature.mode} mode)` }}</span>
                <div class="d-flex ml-auto mr-0  mt-3">
                  <v-btn icon class="ma-0 pa-0" height="auto" width="60px" @click="handleSignature('edit')"
                    ><v-icon small color="primary">mdi-draw</v-icon><span style="font-size: 0.66rem; color:black">{{ $t('editing') }}</span></v-btn
                  >
                </div>
              </div>
              <img :src="signature.data" id="signature_display" width="100%" height="150px" style="padding:0; margin:0;" />
            </div>
          </v-col>
          <v-checkbox class="px-2" :label="$t('changePassword')" color="info" v-model="bChecked" hide-details></v-checkbox>
          <v-col cols="12" v-if="bChecked">
            <v-text-field
              :append-icon="show2 ? 'mdi-eye' : 'mdi-eye-off'"
              :type="show2 ? 'text' : 'password'"
              @click:append="show2 = !show2"
              :label="$t('newPassword')"
              v-model="params.userPs"
              required
              :rules="[rules.required]"
            >
            </v-text-field>
          </v-col>
          <v-col cols="12" v-if="bChecked">
            <v-text-field
              :append-icon="show3 ? 'mdi-eye' : 'mdi-eye-off'"
              :type="show3 ? 'text' : 'password'"
              @click:append="show3 = !show3"
              :label="$t('newPasswordConfirm')"
              v-model="params.userPsConfirm"
              required
              :rules="[rules.required]"
            ></v-text-field>
          </v-col>
        </v-row>
        <small class="ml-1 px-2">{{ $t('msgRequiredInput') }}</small>
      </v-card-text>
      <v-card-actions class="mr-2 pb-4">
        <v-spacer></v-spacer>
        <v-btn small elevation="0" outlined height="28" width="70" class="rounded mr-1" color="btn_bg" @click="close()">
          <div class="float-center mx-1 font-weight-bold" style="color: #0E1113;">{{ $t('btnClose') }}</div>
        </v-btn>
        <v-dialog v-model="okDialog" persistent max-width="290">
          <template v-slot:activator="{ on, attrs }">
            <v-btn small elevation="0" height="28" width="70" class="rounded mr-4" dark color="btn_sub" v-bind="attrs" v-on="on">
              <div class="float-center font-weight-bold">{{ $t('btnSave') }}</div>
            </v-btn>
          </template>
          <v-card class="pa-4">
            <v-card-title class="text-subtitle-1 font-weight-bold pb-0 primary--text">
              {{ $t('confirmPersonalInformation') }}
            </v-card-title>
            <v-card-text class="pa-0 pl-6 mb-4"> {{ $t('msgInfomation') }}</v-card-text>
            <v-card-actions>
              <v-spacer></v-spacer>
              <v-btn small elevation="0" outlined height="28" width="70" class="rounded mr-1" color="btn_bg" @click="okDialog = false">
                <div class="float-center mx-1 font-weight-bold" style="color: #0E1113;">{{ $t('btnCancel') }}</div>
              </v-btn>
              <v-btn small elevation="0" height="28" width="70" class="rounded popBtn2" dark color="btn_sub" @click="save()">
                <div class="float-center font-weight-bold">{{ $t('btnConfirm') }}</div>
              </v-btn>
            </v-card-actions>
          </v-card>
        </v-dialog>
      </v-card-actions>
    </v-card>
  </div>
</template>

<script>
import { AesEncrypt } from '@/utils/aes256' //cyrptojs 적용(aes256)
import { getUserListInfo, savePrivateUser } from '@/api/system/userManage'
import { getCompId, getUserCd } from '@/utils/token'
import { validTell, validEmail } from '@/utils/validate.js'
import sessionStore from '@/utils/sessionStore'

export default {
  name: 'i-user_info',
  components: {},
  props: {
    // onclose: {
    //   type: Function
    // },
  },
  data() {
    return {
      options: {
        penColor: '#c0f'
      },
      bChecked: false,
      userInfo: {},
      refreshKey: 0,
      params: {
        userCd: '',
        sexDiv: '',
        hpNo: '',
        email: '',
        userPs: '',
        userPsConfirm: ''
      },
      okDialog: false,
      show1: false,
      show2: false,
      show3: false,
      error: '',
      //폰패턴: /^(\d{2}||\d{3})-(\d{4}||\d{3})-\d{4}$/i
      //phonePattern: /^(\d{2}||\d{3})-(\d{4}||\d{3})-\d{4}$/i,
      //emailPattern: /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/g,
      rules: {
        required: value => !!value || 'Required.',
        min: v => v.length >= 8 || 'Min 8 characters',
        emailMatch: v => validEmail(v) || v == '' || v == null || this.$t('올바르지 않은 이메일 형식입니다.'),
        phoneMatch: v => validTell(v) || this.$t('올바르지 않은 전화번호 형식입니다.')
      },
      signature: {
        mode: 'display',
        data: '',
        isEmpty: false
      }
    }
  },
  computed: {
    datasource() {
      return this.userInfo
    }
  },
  mounted() {
    this.load()
  },
  activate() {},
  methods: {
    handleSignature(option) {
      this.signature.mode = option
    },
    clearSign() {
      this.$refs.signaturePad.clearSignature()
    },
    saveSign() {
      const { isEmpty, data } = this.$refs.signaturePad.saveSignature()
      this.signature.mode = 'display'
      if (isEmpty == false) {
        this.signature.isEmpty = true
        this.signature.data = data
      }
    },
    async load() {
      this.userInfo = []
      this.params.userCd = getUserCd()
      await getUserListInfo({ compId: this.getCompId(), userCd: this.params.userCd })
        .then(res => {
          if (res.success) {
            this.userInfo = res.list[0]
            this.signature.data = this.userInfo.signature
            this.refreshKey += 1
          }
        })
        .catch(error => {})
    },
    async save() {
      this.error = ''
      const validations = [
        {
          key: 'hpNo',
          check: !(validTell(this.userInfo.hpNo) || this.userInfo.hpNo === '' || this.userInfo.hpNo == null),
          msg: '올바른 형식의 휴대전화번호를 입력하세요.'
        },
        {
          key: 'email',
          check: !(validEmail(this.userInfo.email) || this.userInfo.email === '' || this.userInfo.email == null),
          msg: '올바른 형식의 이메일을 입력하세요.'
        },
        {
          key: 'email2',
          check: this.userInfo.email && this.userInfo.email.length > 50,
          msg: '이메일은 50자 이내로 입력하세요.'
        },
        {
          key: 'ps',
          check: this.bChecked && (!this.params.userPs || !this.params.userPsConfirm),
          msg: '새로운 비밀번호, 새로운 비밀번호(확인)을 입력하세요.'
        },
        {
          key: 'psCheck',
          check: this.bChecked && this.params.userPs !== this.params.userPsConfirm,
          msg: '패스워드와 패스워드확인이 일치하지 않습니다.'
        }
      ]
      for (const { check, key, msg } of validations) {
        if (check) {
          this.error = msg || ''
          this.okDialog = false
          return
        }
      }
      let params = {
        userCd: this.params.userCd,
        sexDiv: this.params.sexDiv,
        hpNo: this.userInfo.hpNo,
        email: this.userInfo.email,
        bChangePassword: this.bChecked,
        signature: this.signature.data,
        userPs: AesEncrypt(this.params.userPs),
        userPsConfirm: AesEncrypt(this.params.userPsConfirm)
      }

      //변경된 서명이 있다면
      if (this.signature.isEmpty == false) {
        params.signature = this.signature.data
      }
      await savePrivateUser(params, true)
        .then(res => {
          if (res.success) {
            this.refreshKey += 1
            this.bChecked = false
          } else this.error = res.msg
        })
        .catch(error => {})
        .finally(() => {
          this.okDialog = false
        })
    },
    close() {
      this.userInfo = []
      this.params = {}
      this.error = ''
      this.okDialog = false
      this.bChecked = false
      this.handleSignature('display')
      this.params.userCd = getUserCd()
      this.$emit('onclose')
    },
    getCompId() {
      return this.$store.state.app.compId ? this.$store.state.app.compId : getCompId()
    }
  }
}
</script>

<style lang="scss" scoped>
//정보변경 스타일 적용 start [[
.theme--light.v-card {
  background-color: #fff !important;
}

#signature {
  border: double 1px transparent;
  border-radius: 3px;
  background-image: linear-gradient(white, white), radial-gradient(circle at top left, #4bc5e8, #9f6274);
  background-origin: border-box;
  background-clip: content-box, border-box;
}

#signature_display {
  border: double 1px transparent;
  border-radius: 3px;
  background-image: linear-gradient(white, white), radial-gradient(circle at top left, #4bc5e8, #9f6274);
  background-origin: border-box;
  background-clip: content-box, border-box;
}

.container {
  width: '100%';
  padding: 8px 16px;
}

.buttons {
  display: flex;
  gap: 8px;
  justify-content: center;
  margin-top: 8px;
}
</style>
