<template>
  <v-list-item @click="moveTo(item)" :to="item.progCd" active-class="service--text">
    <!-- 2022-03-21 lyj level 3까지 메뉴 처리 -->
    <v-list-item-title class="d-flex align-center" v-if="item.lvl <= 1" :class="`menu-level${item.lvl}`">
      <svg-icon v-if="!!item.icon" class="titleIcon mr-2" :icon-class="item.icon"></svg-icon>
      <div class="" style="width: 100%; display:inline-flex;">
        <div class="">
          {{ item[$t('i18n_title')] }}
        </div>
      </div>
    </v-list-item-title>

    <v-list-item-title v-else-if="item.lvl == 2" :class="`menu-level${item.lvl}`">{{ item[$t('i18n_title')] }} </v-list-item-title>
  </v-list-item>
</template>

<script>
export default {
  name: 'DefaultListItem',
  props: {
    item: {
      type: Object,
      default: () => ({})
    }
  },
  data() {
    return {}
  },
  mounted() {
    //console.log('DefaultListItem mounted', this.$route)
  },
  methods: {
    moveTo(to) {

      let toRouter = {
        path: to.progCd,
        name: to.id,
        // query: { topIndex: to.topIndex, tMenu: to.zeroLevelId, selMenuid: to.id, lvl: to.lvl }
        params: {
          topIndex: to.topIndex,
          tMenu: to.zeroLevelId,
          selMenuid: to.id,
          lvl: to.lvl
        }
        //meta: { proc_cd: to.proc_cd, title: to.title, affix: to.affix }
      }
      // 현재 라우터와 동일한 경로로 이동하려는 경우 무시
      if (this.$route.meta.proc_cd !== toRouter.path) {
        try {
          this.$router.push(toRouter);
        } catch (e) {
          console.error(e);
        }
      }
      //console.log(' moveTo towDepthMenuClick')
      this.$emit('towDepthMenuClick', { topIndex: to.topIndex, currentId: to.id, zeroLevelId: to.zeroLevelId })
    }

  }
}
</script>

<style lang="scss" scoped>
.theme--light.v-list-item--active:hover::before,
.theme--light.v-list-item--active::before {
  opacity: 0 !important;
}
</style>
