<template>
  <div class=sideNav>

    <v-navigation-drawer
    v-model="drawer"
    :class="[mini ? 'mini' : '']"
    :mini-variant.sync="mini"
    mini-variant-width="120"
    permanent
    width="240"
    color="footer_bg"
    dark
    :touchless="touchless"
    >
    <v-btn icon @click.stop="mini = !mini" @click="collapseMenu">
      <v-icon class="expandBtn">mdi-chevron-left</v-icon>
    </v-btn>
    <v-list dense nav expand>
      <template v-for="(item, index) in menuTree">
        <default-list-group
        v-if="item.items"
        :key="`group-${index}`"
        ref="listGroupRef"
        :item="item"
        :expanded="groupOpened"
        @towDepthMenuClick="towDepthMenuClick(item, $event)"
        />
        <!-- v-model="groupOpened" -->
        <default-list-item class="" v-else :key="`item-${index}`" :item="item" @towDepthMenuClick="towDepthMenuClick(item, $event)">
        </default-list-item>
      </template>
    </v-list>
  </v-navigation-drawer>
</div>
</template>
<script>
import DefaultListItem from '@/layout/navbar/ListItem' // 단일 메뉴
import DefaultListGroup from '@/layout/navbar/ListGroup' // 그룹 메뉴
import { DxList } from 'devextreme-vue/list'

export default {
  name: 'totalMenu',
  props: {
    menuTree: {
      type: Array,
      required: true,
      default: () => []
    }
  },
  components: { DefaultListItem, DefaultListGroup },
  data() {
    return {
      drawer: true,
      mini: true,
      groupOpened: false,
      touchless: true
    }
  },
  mounted() {
    //  console.log('totalMenu mounted')
    //  console.log(this.menuTree)
  },
  computed: {
    checkExpanded() {
      return item => {
        let matched = false
        if (item.items && item.items.length > 0) {
          console.log(item.title)

          item.items.forEach(m => {
            if (m.id == this.$route.name) {
              matched = true
              console.log(m.title)
            } else {
              if (m.items)
                m.items.forEach(x => {
                  if (x.id == this.$route.name) {
                    matched = true
                    console.log(x.title)
                  }
                })
            }
          })
        }
        console.log(matched)
        return matched
      }
    }
  },
  methods: {
    towDepthMenuClick(item, to) {
      console.log('totalMenu towDepthMenuClick')
      //console.log(to)
      this.$emit('towDepthMenuClick', { topIndex: item.topIndex, currentId: to.currentId, zeroLevelId: to.zeroLevelId })
    },
    collapseMenu() {
      console.log('listGroupRef', this.$refs.listGroupRef)
      this.$refs.listGroupRef.forEach(element => element.collapseMenu())
    },
    activeStyle(mini) {
      return { trasnform: mini ? 'rotate(180dep)' : 'rotate(360dep)' }
    }
  },
  activated() {
    //console.log('pageInnerMenu activated')
  }
}
</script>

