<template>
  <v-list-group :value="getExpanded" v-model="listGroupExpand" active-class="white--text">
    <v-icon slot="appendIcon" color="#5A7C98"></v-icon>
    <template v-slot:appendIcon>
      <svg-icon icon-class="menu_down"></svg-icon>
    </template>
    <template v-slot:activator>
      <v-list-item-title class="d-flex align-center" :class="`menu-level${item.lvl}`">
        <svg-icon v-if="!!item.icon" class="titleIcon mr-2" :icon-class="item.icon"></svg-icon>
        <div class="" style="width: 100%; display:inline-flex;">
          <div class="">
            {{ $t(getMenuTitle) }}
          </div>
        </div>
      </v-list-item-title>
      <!-- <v-icon small class="pr-2" color="nav_title"> {{ item.icon }} </v-icon> -->
    </template>

    <template v-for="(child, index) in item.items">
      <default-list-group v-if="child.items" :key="`sub-group-${index}`" :item="child"></default-list-group>
      <default-list-item class="pl-11" v-else :key="`child-${index}`" :item="child" @towDepthMenuClick="towDepthMenuClick(item, $event)" />
    </template>
  </v-list-group>
</template>

<script>
import DefaultListGroup from './ListGroup'
import DefaultListItem from './ListItem'
export default {
  name: 'DefaultListGroup',
  components: {
    DefaultListItem,
    DefaultListGroup
  },
  props: {
    item: {
      type: Object,
      default: () => ({})
    },
    expanded: {
      type: Boolean,
      default: false
    }
  },
  data() {
    return {
      // expanded: false
      listGroupExpand: false
    }
  },
  mounted() {
    //console.log('DefaultListGroup mounted')
    //console.log('listGroup', this.item)
  },
  computed: {
    getMenuTitle() {
      return this.item[this.$t('i18n_title')]
    },
    getExpanded() {
      //console.log('getExpanded', this.expanded)
      return this.expanded
    }
  },
  methods: {
    // ClickGroup() {
    //   return item => {
    //     console.log('ClickGroup', item.title)
    //     this.matched = false
    //     if (item.items && item.items.length > 0) {
    //       //console.log(this.$route)

    //       item.items.forEach(m => {
    //         if (m.id == this.$route.name) {
    //           this.matched = true
    //         }
    //       })
    //     }
    //   }
    // },
    towDepthMenuClick(item, to) {
      //console.log('towDepthMenuClick')
      //console.log(to)
      this.$emit('towDepthMenuClick', { topIndex: item.topIndex, currentId: to.currentId, zeroLevelId: to.zeroLevelId })
    },
    collapseMenu() {
      this.listGroupExpand = false
    }
  }
}
</script>
