import request from '@/utils/request'
import { isUseAPI } from '@/utils/check'
import targetData from './mock/targetList.json'

export function multiUpload(params, isNotify) {
  let isTest = false
  var baseURL = `/api/file/multiUpload?desc=`
  return request({
    url: baseURL,
    meta: { apiVersion: '1.0.0' },
    method: 'POST',
    headers: { 'Content-Type': 'multipart/form-data' },
    data: params,
    Notify: { use: isNotify, apitype: 'saved' } 
  })
}
