import { AesDecrypt, AesEncrypt } from '@/utils/aes256';

const sessionStore = {
    get: (stringkey) => {
        if (typeof stringkey !== 'string') {
            alert('key data is not string.');
            return null;
        }
        const encryptedData = sessionStorage.getItem(stringkey);
        if (encryptedData) {
            const decryptedData = AesDecrypt(encryptedData);
            try {
                return decryptedData; // JSON 파싱
            } catch (error) {
                console.error('Failed to parse decrypted data:', error);
                return null;
            }
        }
        return null;
    },

    set: (stringkey, stringData) => {
        if (typeof stringkey !== 'string' || typeof stringData !== 'string') {
            alert('key and data must be strings.');
            return null;
        }
        const encryptedData = AesEncrypt(stringData);
        sessionStorage.setItem(stringkey, encryptedData);
    }
};

export default sessionStore;
