<script>
// Logout 정의 부분
// 유저 정보와 토큰을 삭제한 이후, 화면을 재갱신한다.
// 자동적으로 /login 화면으로 이동
export default {
  name: 'logout',
  created () {
    this.$store.dispatch('Logout').then(() => {
      // 20240719 동적 라우팅 구성 정보를 초기화하기 위해 강제로 새로고침 적용
      location.reload(true) 
      this.$router.push("/login")
    })
  },
  render: (h) => h()
}
</script>
