import { getUser, logout, reissueToekn } from '@/api/common/login'
import {
  getToken,
  removeToken,
  setUserCd,
  setToken,
  setRefreshToken,
  setCookieToken, setCookieUserCd, setUserInfo, setCookieAutoLogin, setCookieCompId,setCookieIocale
} from '@/utils/token'
import { AesEncrypt } from '@/utils/aes256' //cyrptojs 적용(aes256) by lyj 20220404

export default {
  state: {
    token: '',
    usercd: '',
    userName: '',
    clntId: '',
    compId: '',
    plntId: '',
    empNo: '',
    deptCd: '',
    bpCd: '',
    jbl: '',
    jbrp: '',
    trad: '',
    dimDiv: '',
    foreignYn: '',
    roles: [],
    auths: [],
    menuAuthGroup: '',
    menuPermission: '',
    registName: '',
    registPhoneNumber: '',
    buttonPermission: '',
    myMenu: []
  },

  //데이터 변경시
  mutations: {
    SET_TOKEN: (state, token) => {
      state.token = token
    },
    SET_USER_ID: (state, usercd) => {
      state.usercd = usercd
    },
    SET_USER_NAME: (state, userName) => {
      state.userName = userName
    },
    // SET_DOMAIN_CD: (state, domainCd) => {
    //   state.domainCd = domainCd
    // },2022-03-15 domain 개념 삭제 by yjlim
    SET_DIM_DIV: (state, dimDiv) => {
      state.dimDiv = dimDiv
    },
    SET_FOREIGN: (state, foreignYn) => {
      state.foreignYn = foreignYn
    },
    SET_ROLES: (state, roles) => {
      state.roles = roles
    },
    SET_AUTHS: (state, auths) => {
      state.auths = auths
    },
    SET_MENU_AUTH_GROUP: (state, menuAuthGroup) => {
      state.menuAuthGroup = menuAuthGroup
    },
    SET_COOKIE_TOKEN: (state, token) => {
      state.token = token
    }
  },

  //methods
  actions: {
    //윤주
    LoginByPassword({ commit }, params) {
      {
        let token = params.login_res.map.accessToken;
        let refreshToken = params.login_res.map.refreshToken;
        let userCd = params.userInfo.usercd;
        let resUserCd = params.login_res.map.userCd;
        let isAutoLogin = params.userInfo.isAutoLogin;
        let compId = params.userInfo.compId;

        //#region set session
        if(userCd !== resUserCd){
          return;
        }
        setToken(token)
        setRefreshToken(refreshToken)
        setUserCd(resUserCd)
        //#endregion

        // console.log('loginByPassword - session --> ' + userCd)
        // console.log(params)

        //region set Cookie
        setCookieToken(token);
        setCookieUserCd(resUserCd)
        setCookieCompId(compId)
        setCookieIocale()
        //endregion

        //자동로그인 체크
        setCookieAutoLogin(isAutoLogin);
        if (isAutoLogin === true) {
          let userToken = getToken()
          setToken(userToken)
        }
      }
    },
    SetUserInfo({ commit }, userInfo) {
      return new Promise((resolve, reject) => {
        getUser(userInfo.usercd)
          .then(response => {
            const userinfo = response.list && response.list[0] ? response.list[0] : null;
            if (!userinfo) {
              throw new Error('No user information found');
            }
            console.log('loginresponse', JSON.stringify(userinfo));

            const token = getToken(); // 토큰을 한 번만 호출하여 변수에 저장
            commit('SET_USER_ID', userinfo.usercd);
            commit('SET_USER_NAME', userinfo.userNm);
            commit('SET_MENU_AUTH_GROUP', userinfo.grpauthcd); // 로그인 사용자의 권한 그룹 정보 (super/master/manager/normal)
            commit('SET_TOKEN', token);
            commit('SET_COOKIE_TOKEN', token);

            const userinfoList = [
              { id: 'compId', content: userinfo.compid },
              { id: 'compNm', content: userinfo.compnm },
              { id: 'userCd', content: userinfo.usercd },
              { id: 'grpAuthCd', content: userinfo.grpauthcd }
            ];
            setUserInfo(userinfoList); // 최적화된 setUserInfo 함수 사용 
            resolve();
          })
          .catch(error => {
            reject(error);
          });
      });
    },

    //토큰 재발급 후 세션에 새로운 토큰 저장
    reissueToekn({ commit }, tokenInfo) {
      return new Promise(function(resolve, reject) {
        reissueToekn(tokenInfo)
          .then(response => {
            //console.log('토큰재발급완료! ', response.accessToken)
            setToken(response.accessToken)
            if (response.refreshToken) {
              //refresh toke은 만료기간이 7일이전에만 재발급함
              //console.log('refresh token 재발급완료! ', response.refreshToken)
              setRefreshToken(response.refreshToken)
            }
          })
          .then(() => {
            resolve()
          })
          .catch(error => {
            reject(error)
          })
      })
    },
    Logout({ dispatch }) {
      return new Promise((resolve, reject) => {
        logout().then(() => {
          window.sessionStorage.clear()
          //모든 tagviews clear
          dispatch('tagsView/delAllViews') //20220406 LYJ 로그아웃시 모든 tagView 삭제 처리
          dispatch('app/setInfoForConfig', {}) //store에 정보 저장
          dispatch('ClearSession')
          resolve()
        })
      })
    },
    ClearSession({ commit }) {
      commit('SET_USER_ID', '')
      commit('SET_USER_NAME', '')
      commit('SET_MENU_AUTH_GROUP', '')
      // commit('SET_DOMAIN_CD', '')2022-03-15 domain 개념 삭제 by yjlim
      commit('SET_TOKEN', '')
      window.sessionStorage.clear()
      
      removeToken()
    }
  },

  //computed
  getters: {}
}
