<template>
            <div class="d-flex flex-column justify-center fill-width mt-15">
              <svg-icon class="mb-4" style="height: 422px;" icon-class="404-error"></svg-icon>
              <v-card-title class="justify-center text-h3 text-black service--text mb-2">
                <b>404 ERROR</b>
              </v-card-title>
              <v-card-subtitle class="sub_title--text text-center mb-4">
                <b>{{ $t('errorTitle') }} {{ $t('errorSubTitle') }}</b>
              </v-card-subtitle>
            </div>
</template>

<script>
export default {
  name: 'pageNotFound',
  data: () => ({
    show: false
  }),
  mounted(){
    setTimeout(() => {      
      this.back()
    }, 100);
  },
  methods: {
    back() {      
      alert(this.$t('errorMsgNotFoungPage'))
      this.$router.go(-1).catch(() => {})
    },     
    goMain() {
      this.$router.push('/dashboard').catch(error => {
        if (error.name === 'NavigationDuplicated') console.log('NavigationDuplicated')
        else console.log(error)
      })
    },
    // TODO 다국어 세팅 한 곳에 모아서 처리하도록 적용 필요
    // 다국어 세팅
    setLocale() {
      if (!sessionStorage.getItem('locale')) {
        sessionStorage.setItem('locale', this.$vuetify.lang.current)
      } else {
        if (sessionStorage.getItem('locale') === 'ko') {
          this.$vuetify.lang.current = 'ko'
          this.$i18n.locale = 'ko'
        } else {
          this.$vuetify.lang.current = 'en'
          this.$i18n.locale = 'en'
        }
      }
    }
  }
}
</script>

