import request from '@/utils/request'

//사업장 별 공정 정보 조회
//param : compId(사업장번호) ex) getAllProcess("IGNS")
export function getAllProcess(param) {
  return request({
    url: '/api/common/getAllProcess',
    method: 'POST',
    headers: { 'Content-Type': 'application/json;charset=utf8' },
    data: param,
    meta: { apiVersion: '1.0.0' }
  })
}

