import { getAuthMenuById } from '@/api/common/menu'
import store from '@/store'
import sessionStore from '@/utils/sessionStore'
//import { getMenuData } from '@/api/system/menuManage' // 메뉴 api 호출
import { getMenuOfgroupManage } from '@/api/setting/menuOfgroupManage'
import { getGrpAuthCd } from '@/utils/token'
import { getAuthMenuRouteById } from '@/api/common/menu'
import Layout from '@/layout/layout.vue'
import router from '@/router'
import { resetRouter } from '@/router'
import { AesEncrypt } from '@/utils/aes256'
import pageNotFound from '@/views/error/404'

// 동적 라우팅 배열
let DynamicRouteInfo = []

// 아이콘 리스트
const icons = [
  { icon: 'folder', level: 0 },
  { icon: 'menulvl1', level: 1 },
  { icon: 'menulvl2', level: 2 },
  { icon: 'menulvl3', level: 3 }
]

//tree 구성
var SidemenuUtils = {
  // 기본 아이콘 사용 또는 사용자 정의 아이콘 사용
  findIcon(item) {
    //console.log('##icon 1 '+ icons.find(icon => icon.level === item.level).icon)
    if (!item.icon && !item.icon === '') {
      return icons.find(icon => icon.level === item.level).icon
    }
    if (item.icon === '') {
      return icons.find(icon => icon.level === item.level).icon
    }
    return item.icon
  }
}

function recursiveSetZeroLvlId(list, zeroLevelId) {
  list.forEach(m => {
    m.zeroLevelId = zeroLevelId
    // console.log(m.title + '/' + zeroLevelId + '/')
    if (m.items) {
      recursiveSetZeroLvlId(m.items, zeroLevelId)
    } else return
  })
}

export default {
  state: {
    menus: [],
    treeMenus: [],
    flag: {
      asideVisiable: true,
      asideUse: true,
      tagViewUse: true,
      headerUse: true,
      footerUse: true,
      myMenuVisible: false,
      fullscreen: false,
      isLayoutHideMode: false
    }
  },

  //data를 변경할때
  mutations: {
    // 전체 화면에서 레이아웃을 다 감추는 모드 사용 여부
    SET_LAYOUT_HIDE_MODE(state, flag) {
      state.flag.isLayoutHideMode = flag
    },
    SET_HEADER_USE: function(state, flag) {
      state.flag.headerUse = flag
    },
    SET_TAG_VIEW_USE: function(state, flag) {
      state.flag.tagViewUse = flag
    },
    SET_ASIDE_MENU_USE: (state, flag) => {
      state.flag.asideUse = flag
    },
    SET_FOOTER_USE: function(state, flag) {
      state.flag.footerUse = flag
    },
    SET_FULLSCREEN: function(state, flag) {
      state.flag.fullscreen = flag
    },
    // SET_MENU: (state, menus) => {
    //   state.menus = menus
    // }
    SET_TREE_MENU: (state, treeMenus) => {
      state.treeMenus = treeMenus
    },
    SET_MY_AUTH_GRPS: (state, menus) => {
      state.myAuthGrps = menus
    }
  },

  //methods
  actions: {
    GetMenus({ commit }, userInfo) {
      //console.log('######userInfo --> ' + JSON.stringify(userInfo))
      return new Promise((resolve, reject) => {
        // 초기화
        //commit('SET_MENU', [])
        commit('SET_TREE_MENU', [])
        DynamicRouteInfo = []

        // 동적 라우팅 처리 - 사용자권한메뉴 Route 셋팅 (로그인 후 메뉴 라우터에 push)
        getAuthMenuRouteById({ usercd: userInfo.usercd, svcGubn: 'W' })
        .then(response => {
          response.list.forEach(route => {
            if (route.svcType == 'P') {
              // 준비중
              route.path = '/error'
              route.component = `preparing`
            } else if (route.svcType == 'I') {
              // 점검중
              route.path = '/error'
              route.component = `inspection`
            } else if (!route.component) {
              // 프로그램관리 > 라우터 컴포넌트 확인
              route.path = '/error'
              route.component = `404`
            }
      
            let newRoute = {
              path: `/${route.progCd}`,
              component: () => import(`@/views${route.path}/${route.component}.vue`),
              name: `${route.menuId}`, //`${route.name}_index`,
              meta: { proc_cd: `${route.progCd}`, title: `${route.progNm}`, affix: `${route.affix}` == 'Y' ? true : false },
              // query: { tMenu: '2' }
              params: {
                tMenu: '2'
              }
            }
            DynamicRouteInfo.push(newRoute)
          })
          //init route
          resetRouter()
          let newRoute = {
            path: '/',
            redirect: '/dashboard',
            component: Layout,
            children: DynamicRouteInfo
          }
          let notFound={
            path: '*',
            name: 'pageNotFound',
            component: pageNotFound
          }
          router.addRoutes([newRoute,notFound])
        })
        .catch(error => {
          console.log(error)
        })
        .finally(() => { })        
        
        // console.log('**api!!')
        // 사용자권한메뉴조회
        getAuthMenuById({ usercd: userInfo.usercd, svcGubn: 'W' })
          .then(responseAuth => {
            //20220323 LYJ [메뉴 정렬 문제] 우선적으로는 이렇게 처리함, 백엔드에서 정렬안됨
            responseAuth.list.reverse()
            //console.log('########## authMenu : ' + JSON.stringify(responseAuth.list))
            //console.log(responseAuth.list)

            let list = responseAuth.list
            list.forEach(menu => {
              menu.zeroLevelId = menu.id
              if (menu.items) recursiveSetZeroLvlId(menu.items, menu.id)
            })
            
            // 20240719 myAuthMenus session storage 사용 중지, state 사용
            // sessionStore.set('myAuthMenus', JSON.stringify(list))
            commit('SET_TREE_MENU', list)
            resolve()
          })
          .catch(error => {
            reject(error)
          })
        
        //권한 그룹별 메뉴 접근 권한 정보 조회 by lyj
        let params = {
          svcGubn: 'W', // web
          grpAuthCd: getGrpAuthCd(),
          auth: '' // vuetify의 라디오 value는 "" 을 넣으면 0으로 나와서 "" 으로 바꿔줌
        }
        getMenuOfgroupManage(params)
          .then(responseMenuGrp => {
            // 20240719 myAuthGrps session storage 사용 중지, state 사용 
            // sessionStore.set('myAuthGrps',JSON.stringify(responseMenuGrp.list))
            commit('SET_MY_AUTH_GRPS', responseMenuGrp.list)
            resolve()
          })
          .catch(error => {
            reject(error)
          })
      })
    },

    SetHeaderUse({ commit }, flag) {
      if (typeof flag !== 'boolean') return
      commit('SET_HEADER_USE', flag)
    },
    SetTagViewUse({ commit }, flag) {
      if (typeof flag !== 'boolean') return
      commit('SET_TAG_VIEW_USE', flag)
    },
    SetASideMenuUse({ commit }, flag) {
      if (typeof flag !== 'boolean') return
      commit('SET_ASIDE_MENU_USE', flag)
    },
    SetFooterUse({ commit }, flag) {
      if (typeof flag !== 'boolean') return
      commit('SET_FOOTER_USE', flag)
    },
    SetLayoutHideMode({ commit }, flag) {
      if (typeof flag !== 'boolean') return
      commit('SET_LAYOUT_HIDE_MODE', flag)
    },
    SetFullScreen({ commit }, flag) {
      if (typeof flag !== 'boolean') return
      commit('SET_FULLSCREEN', flag)
      if (store.state.menu.flag.isLayoutHideMode === true) {
        commit('SET_HEADER_USE', !flag)
        commit('SET_TAG_VIEW_USE', !flag)
        commit('SET_ASIDE_MENU_USE', !flag)
        commit('SET_FOOTER_USE', !flag)
      }
    }
  },

  getters: {
    //computed
  }
}
