<template>
  <v-container fluid fill-height pa-0 login_bg>
    <v-layout align-center justify-center pa-0>
      <v-flex xs10 sm8 md6 lg6>
        <v-row no-gutters>
          callbackNaverLogin.vue
        </v-row>
        </v-flex>
    </v-layout>
  </v-container>
</template>

<script>
import envs from '@/envs'

export default {
  //layout: 'layout_login',
  data() {
    return {
      userData: {
        usercd: '',
        userps: '',
        isAutoLogin: false
      },
    }
  },
  mounted() {
    console.log('callbackNaverLogin.vue')
    const naverLogin = new window.naver.LoginWithNaverId({
      clientId:  envs.naverAuthClientId
    })
    naverLogin.init()
    naverLogin.getLoginStatus(function(status) {
      if (status) {
        const info = {
          id: naverLogin.user.id,
          age: naverLogin.user.age,
          gender: naverLogin.user.gender,
          nickname: naverLogin.user.nickname,
          profile_image: naverLogin.user.profile_image,
        }

        alert(naverLogin.user.id)
        console.log('info',info)
      } else {
        console.log('AccessToken이 올바르지 않습니다.') 
      }
    })
  }
}
</script>
