<template>
  <v-container fluid fill-height pa-0>
    <v-img :src="loginBg" alt="logo" cover class="login_background" />
    <i-dxpopup
      :popupVisible="popupVisible"
      :title="popupTitle"
      @popupCloseButtonClick="popupCloseButtonClick"
      :vHtmlContent="'test'"
      :height="popupHeight"
      :width="popupWidth"
      :min-width="popupMinWidth"
    >
      <template v-slot:grid>
        <login-sign :key="componentKey" ref="popUp" @popupClose="popupVisible = false"> </login-sign>
      </template>
    </i-dxpopup>
    <!-- light 테마일 경우 나오는 layout -->
    <v-layout align-center justify-center pa-0>
      <v-app-bar fixed outlined elevation="0" color="#ffffff00" class="d-flex justify-space-between">
        <v-img :src="require(`@/assets/images/logo/logo.png`)" width="150%" contain max-width="250" max-height="50" class="py-3 ml-2" />
        <template #extension>
          <ilang class="pt-4"/>
        </template>
      </v-app-bar>
      <v-flex class="overflow-hidden">
        <v-row no-gutters>
          <v-col cols="12" class="fill-height  justify-center d-flex">
            <v-card class="elevation-2 pt-8 rounded-xl" height="600" width="50vw" max-width="500" dark color="#13213CCC">
              <v-card-text class="text-center px-lg-8 px-6 pb-0">
                <div class="d-inline-block justify-center">
                  <p class="pa-0 ma-0 mt-1 mb-8 white--text font-weight-light d-block" style="font-size:1rem; font-weight: 900;">
                    Thank you for coming!
                  </p>
                </div>
                <v-form class="pt-1">
                  <v-text-field
                    v-model="userData.compId"
                    class="py-5 my-5"
                    name="company"
                    autocomplete="off"
                    label="Factory ID"
                    color="service"
                    type="text"
                    :maxlength="10"
                    @keyup.enter="signIn()"
                  >
                    <template v-slot:prepend-inner>
                      <svg-icon style="height:1.2rem; margin-top: 7px; margin-left: 10px; color:#2CCCEF;" icon-class="company"></svg-icon>
                    </template>
                  </v-text-field>

                  <v-text-field
                    v-model="userData.suffixUsercd"
                    class="py-5 my-5"
                    name="login"
                    autocomplete="off"
                    label="User ID"
                    color="service"
                    type="text"
                    :maxlength="100"
                    @keyup.enter="signIn()"
                  >
                    <template v-slot:prepend-inner>
                      <svg-icon style="height:1.2rem; margin-top: 7px; margin-left: 10px;" icon-class="person"></svg-icon>
                    </template>
                  </v-text-field>
                  <v-text-field
                    v-model="userData.userps"
                    class="py-5 my-5"
                    name="password"
                    id="password"
                    color="service"
                    autocomplete="off"
                    label="Password"
                    :type="value ? 'password' : 'text'"
                    @click:append="() => (value = !value)"
                    :append-icon="value ? 'mdi mdi-eye-off' : 'mdi mdi-eye'"
                    @keyup.enter="signIn()"
                  >
                    <template v-slot:prepend-inner>
                      <svg-icon style="height:1.2rem; margin-top: 7px; margin-left: 10px;" icon-class="password"></svg-icon>
                    </template>
                  </v-text-field>
                </v-form>
                <div id="naverIdLogin" v-if="false"></div>
                <div class="d-flex justify-space-between">
                  <v-checkbox color="service" v-model="userData.isAutoLogin" :label="$t('autoLogin')" />
                  <v-btn elevation="0" text color="service" small @click="ShowPopup($t('join'))">{{ $t('join') }}</v-btn>
                </div>
              </v-card-text>

              <v-card-actions class="px-lg-8 px-6 ">
                <v-btn block x-large height="50" color="service" class="login_footer--text font-weight-bold rounded-xl mt-16" @click="signIn()">{{
                  $t('login')
                }}</v-btn>
              </v-card-actions>
            </v-card>
          </v-col>
        </v-row>
      </v-flex>
      <v-footer color="rgba(26, 28, 30, 0.7)" min-width="100%" fixed class="d-flex justify-center pa-3">
        <div class="white--text mb-0 text-caption" flat tile>
          Copyright © Panasia All Rights reserved
        </div>
      </v-footer>
      <!-- </v-layout> -->
    </v-layout>
    <v-snackbar v-model="snackbar" :timeout="timeout" color="error" top>
      {{ msg }}
    </v-snackbar>
  </v-container>
</template>
<script>
import { fn_AutoLogin, fn_Login, fn_LoginSuccess, naverService } from '@/framework/login/login'
import { getApprovalCheck, getCompanyCheck, getConnectTimeCheck, getFireAtCheck, getUserCdCheck } from '@/api/baseManage/memberApprovalManage'
import { AesEncrypt, AesDecrypt } from '@/utils/aes256' //cyrptojs 적용(aes256) by lyj 20220404
import LoginSign from './LoginSign.vue'
import sessionStore from '@/utils/sessionStore'
import iDxPopup from '@/components/common/iDxPopup.vue'
import { getCookieCompId, setCompId } from '@/utils/token'

import ilang from '@/components/options/iLang.vue'
export default {
  components: {
    'i-dxpopup': iDxPopup,
    LoginSign,
    ilang
  },
  data() {
    return {
      login: require('@/assets/images/ci/login.png'),
      loginBg: require('@/assets/images/bg/login.jpg'),
      // user: require('@/assets/icons/svg/user.svg'),
      userData: {
        compId: getCookieCompId(),
        usercd: '',
        suffixUsercd: '',
        userps: '',
        isAutoLogin: false
      },
      snackbar: false,
      msg: '',
      timeout: 5000,
      value: String,
      componentKey: 0,
      isCapsLockOn: false,

      popupVisible: false,
      popupHeight: '',
      popupWidth: '',
      popupMinWidth: '',
      popupTitle: 'Join'
    }
  },
  mounted() {
    naverService().setNaver()
  },
  created() {
    this.setLocale()
  },
  methods: {
    forceRerender() {
      this.componentKey += 1
    },
    loginWithNaver() {
      const naverLogin = new window.naver.LoginWithNaverId({
        clientId: 'vJvcIyKmtWGybXoCT2hR', // Naver client key
        callbackUrl: 'http://localhost:8080/login/naver',
        callbackHandle: false
      })
      naverLogin.init()
      //naverLogin.reprompt()
    },
    // 로그인
    signIn() {
      this.userData.usercd = this.userData.compId + '_' + this.userData.suffixUsercd
      //TODO : 한개의 API로 수정, 앱도 수정 요청
      setCompId(this.userData.compId)
      fn_Login(this.userData).then(res => {
        if (res.code && res.code != 200) {
          this.snackbar = true
          this.msg = res.msg
          return
        } else if (res.result) {
          fn_LoginSuccess()
        } else {
          this.snackbar = true
          this.msg = res.msg
        }
      })
    },
    ShowPopup(title) {
      this.popupTitle = title
      this.popupHeight = '580'
      this.popupWidth = '480'
      this.popupMinWidth = '460'

      this.forceRerender()
      this.popupVisible = true
    },
    popupCloseButtonClick() {
      this.forceRerender()
      this.popupVisible = false
    },
    // 다국어 세팅
    setLocale() {
      if (!sessionStore.get('locale')) {
        sessionStore.set('locale', this.$vuetify.lang.current)
      } else {
        if (sessionStore.get('locale') === 'ko') {
          this.$vuetify.lang.current = 'ko'
          this.$i18n.locale = 'ko'
        } else {
          this.$vuetify.lang.current = 'en'
          this.$i18n.locale = 'en'
        }
      }
    },
    changeTheme(theme) {
      if (theme) {
        sessionStore.set('theme', 'dark')
      } else {
        sessionStore.set('theme', 'light')
      }
    }
  }
}
</script>

<style scoped>
.login_background {
  position: absolute;
  top: 0;
  left: 0;
  height: 100vh;
  width: 100vw;
}

.login-bg-dark {
  position: fixed;
  background: #464543;
}

.login-bg-light {
  position: fixed;
  background-size: cover !important;
}

.theme--light.v-app-bar.v-toolbar.v-sheet {
  background: #fff;
}

.v-input {
  max-width: 100%;
}

.login_btn {
  background: linear-gradient(98.35deg, #725cf7 -56.47%, #6463f4 30.57%, #2a47da 87.89%, #3227bb 112.31%), #2d3bcf;
  font-size: 1.13rem !important;
}

.rounded-border-lg {
  border-radius: 50px !important;
  border-top-right-radius: 0px !important;
}

.rounded-border-xl {
  border-bottom-right-radius: 100px !important;
}
</style>
