<template>
  <v-footer style="display:flex; font-size: 0.65rem;" min-width="100%" class="flex-column pa-0">
    <v-card color="footer_bg" flat tile width="100%">
      <v-btn
        v-scroll="onScroll"
        color="primary"
        v-show="fab"
        class="floatingTop"
        width="50"
        height="50"
        dark
        small
        absolute
        @click="toTop"
        style="border-radius:0px 20px 0px 5px; right:30px; top:16px"
      >
        <svg-icon icon-class="toTop"></svg-icon>
      </v-btn>
      <div class="footer_wrap">
        <v-row no-gutters>
          <v-col cols="1" class="pa-0 pt-1">
            <v-img :src="require(`@/assets/images/logo/logo.png`)" min-width="180" max-width="180" height="30" contain to="#" />
          </v-col>
          <v-col cols="11" class="pl-3 pt-1 text-center">
            <div class="address d-flex mt-3 mt-md-1 mb-2 justify-center">
              <div class="white--text mr-md-2">
                {{ $t('CEO') }}
                <span class="font-weight-bold ">{{ companyInfo.rpstNm }}</span>
                |
              </div>
              <div class="white--text">
                <span class="font-weight-bold mr-md-2">{{ companyInfo.addrs1 }} ({{ companyInfo.addrs2 }})</span>
                {{ `|  ${$t('tel')}` }}
                <span class="font-weight-bold mr-md-2">{{ companyInfo.telNo }}</span>
                {{ `|  ${$t('fax')}` }}
                <span class="font-weight-bold mr-md-2">{{ companyInfo.faxNo }}</span>
                {{ `|  ${$t('zipCd')}` }}
                <span class="font-weight-bold mr-md-2">{{ companyInfo.zipCd }}</span>
                {{ `|  ${$t('footerEamil')}` }}
                <span class="font-weight-bold mr-md-2">{{ companyInfo.email }}</span>
              </div>
            </div>
          </v-col>
        </v-row>
      </div>
      <v-divider />

      <div class="footer_wrap">
        <v-row no-gutters class="mt-1 mb-2 pl-3">
          <v-col cols="12">
            <div class="white--text text-center">
              {{ companyInfo.desc }}
            </div>
          </v-col>
          <v-col cols="12">
            <div class="mt-3 text-center">
              <span style=" color: #9f9f9f;">Copyright © Panasia All Rights reserved</span>
            </div>
          </v-col>
        </v-row>
      </div>
    </v-card>
  </v-footer>
</template>

<script>
export default {
  name: 'Footer',
  props: {
    companyInfo: Object
  },
  data: () => ({
    fab: false
  }),
  methods: {
    toTop() {
      window.scrollTo({ top: 0, behavior: 'smooth' })
    },
    onScroll(e) {
      if (typeof window === 'undefined') return
      const top = window.pageYOffset || e.target.scrollTop || 0
      this.fab = top > 20
    }
  }
}
</script>

<style scoped>
.footer_wrap {
  max-width: 1280px;
  padding: 10px;
  margin: 0 auto;
  position: relative;
}
</style>
